def _strip_cols(df: pd.DataFrame) -> pd.DataFrame:
    df = df.copy()
    df.columns = [c.strip() if isinstance(c, str) else c for c in df.columns]
    return df

def normalize_cat_text(s: pd.Series) -> pd.Series:
    s = s.astype(str)
    s = s.str.replace("\u00a0", " ", regex=False)
    s = s.str.replace(r"\s+", " ", regex=True)
    s = s.str.strip()
    return s

def normalize_categorical_df(df: pd.DataFrame, cat_cols) -> pd.DataFrame:
    df = df.copy()

    for c in cat_cols:
        if c in df.columns:
            df[c] = normalize_cat_text(df[c])

    # cervix text
    if "CT" in df.columns:
        df["CT"] = df["CT"].astype(str).str.replace(
            r"^\s*cervix\s*$", "Cervix",
            regex=True, flags=re.IGNORECASE
        )

    # Other / Others / other / others -> Other
    for c in cat_cols:
        if c in df.columns:
            df[c] = df[c].astype(str).str.replace(
                r"^\s*othersfigure\s*$", "Other",
                regex=True, flags=re.IGNORECASE
            )

    return df

def apply_semantic_mapping(df: pd.DataFrame) -> pd.DataFrame:
    df = df.copy()
    if "Type" in df.columns:
        df["Type"] = df["Type"].replace(TYPE_MAPPING)
    if "TM" in df.columns:
        df["TM"] = df["TM"].replace(TM_MAPPING)
    if "MAT" in df.columns:
        df["MAT"] = df["MAT"].replace(MAT_MAPPING)
    return df

def clean_2024(df: pd.DataFrame) -> pd.DataFrame:
    df = _strip_cols(df)

    if "No" in df.columns:
        df = df.drop(columns=["No"], errors="ignore")

    de_cols = [c for c in df.columns if isinstance(c, str) and c.startswith("DE_")]
    if TARGET_DE not in df.columns:
        raise ValueError(f"text {TARGET_DE} text DE text {de_cols}")

    if not KEEP_OTHER_DE_AS_FEATURES:
        drop_de = [c for c in de_cols if c != TARGET_DE]
        df = df.drop(columns=drop_de, errors="ignore")

    df = normalize_categorical_df(df, BASE_CAT_COLS)
    df = apply_semantic_mapping(df)

    for c in ["Size", "Zeta Potential", "Admin"]:
        if c in df.columns:
            df[c] = pd.to_numeric(df[c], errors="coerce")

    df[TARGET_DE] = pd.to_numeric(df[TARGET_DE], errors="coerce")
    return df

def pick_features(df: pd.DataFrame, candidates):
    cols = [c for c in candidates if c in df.columns]
    if len(cols) == 0:
        raise ValueError("text text ")
    return cols


# =========================
# 2) text train/test
# =========================
def group_train_test_split(df: pd.DataFrame,
                           group_cols,
                           test_size=0.2,
                           random_state=42,
                           na_token="<NA>"):
    df = df.copy()
    group_cols = [c for c in group_cols if c in df.columns]
    if len(group_cols) == 0:
        raise ValueError("group_cols text text group split ")

    tmp = df[group_cols].copy()
    tmp = tmp.replace({np.nan: na_token}).astype(str)

    gid = tmp.apply(
        lambda r: hashlib.md5("||".join(r.values).encode("utf-8")).hexdigest(),
        axis=1
    )
    df["_group_id"] = gid
    unique_groups = df["_group_id"].dropna().unique()

    g_train, g_test = train_test_split(
        unique_groups, test_size=test_size, random_state=random_state
    )

    df_train = df[df["_group_id"].isin(g_train)].copy()
    df_test  = df[df["_group_id"].isin(g_test)].copy()

    group_id_train = df_train["_group_id"].to_numpy()
    group_id_test  = df_test["_group_id"].to_numpy()

    df_train = df_train.drop(columns=["_group_id"])
    df_test  = df_test.drop(columns=["_group_id"])

    return df_train, df_test, group_id_train, group_id_test


# =========================
# 3) OneHot / Scaler / Preprocess
# =========================
def make_onehot_encoder(min_freq=2):
    try:
        return OneHotEncoder(
            drop="first",
            sparse_output=False,
            handle_unknown="infrequent_if_exist",
            min_frequency=min_freq
        )
    except TypeError:
        return OneHotEncoder(
            drop="first",
            sparse=False,
            handle_unknown="infrequent_if_exist",
            min_frequency=min_freq
        )

def build_preprocessor(numeric_features, categorical_features, scaler_mode="standard"):
    transformers = []

    if len(numeric_features) > 0:
        numeric_steps = [("imputer", SimpleImputer(strategy="median"))]
        if scaler_mode == "standard":
            numeric_steps.append(("scaler", StandardScaler()))
        elif scaler_mode == "minmax":
            numeric_steps.append(("scaler", MinMaxScaler()))
        elif scaler_mode == "robust":
            numeric_steps.append(("scaler", RobustScaler()))
        elif scaler_mode == "none":
            pass
        else:
            raise ValueError(f"text scaler_mode: {scaler_mode}")

        numeric_transformer = Pipeline(steps=numeric_steps)
        transformers.append(("num", numeric_transformer, numeric_features))

    if len(categorical_features) > 0:
        categorical_transformer = make_onehot_encoder(min_freq=OHE_MIN_FREQUENCY)
        transformers.append(("cat", categorical_transformer, categorical_features))

    if len(transformers) == 0:
        raise ValueError("numeric_features text categorical_features text text preprocessor ")

    preprocessor = ColumnTransformer(transformers=transformers)
    return preprocessor

def get_feature_names_after_preprocess(preprocessor):
    try:
        return preprocessor.get_feature_names_out().tolist()
    except Exception:
        feature_names = []
        try:
            for name, trans, cols in preprocessor.transformers_:
                if name == "remainder" and trans == "drop":
                    continue
                if hasattr(trans, "get_feature_names_out"):
                    try:
                        fn = trans.get_feature_names_out(cols)
                    except Exception:
                        fn = trans.get_feature_names_out()
                    feature_names.extend(list(fn))
                else:
                    feature_names.extend(list(cols))
        except Exception:
            feature_names = []
        return feature_names


