# 4) text text
# =========================
def random_oversample_any(X, y, seed=42):
    rng = np.random.default_rng(seed)
    y = pd.Series(y).reset_index(drop=True)

    vc = y.value_counts()
    if len(vc) < 2:
        if isinstance(X, pd.DataFrame):
            return X.reset_index(drop=True).copy(), y.to_numpy()
        return np.asarray(X), y.to_numpy()

    major = vc.idxmax()
    minor = vc.idxmin()
    n_major = vc.max()
    n_minor = vc.min()

    if n_major == n_minor:
        if isinstance(X, pd.DataFrame):
            return X.reset_index(drop=True).copy(), y.to_numpy()
        return np.asarray(X), y.to_numpy()

    idx_major = np.where(y == major)[0]
    idx_minor = np.where(y == minor)[0]
    add_idx = rng.choice(idx_minor, size=(n_major - n_minor), replace=True)

    all_idx = np.concatenate([idx_major, idx_minor, add_idx])
    all_idx = rng.permutation(all_idx)

    if isinstance(X, pd.DataFrame):
        X_bal = X.iloc[all_idx].reset_index(drop=True).copy()
    else:
        X_np = np.asarray(X)
        X_bal = X_np[all_idx]

    y_bal = y.iloc[all_idx].to_numpy()
    return X_bal, y_bal

def compute_class_weight_dict(y):
    y = pd.Series(y)
    vc = y.value_counts()
    if len(vc) < 2:
        return None
    total = vc.sum()
    w = {int(cls): float(total / (len(vc) * cnt)) for cls, cnt in vc.items()}
    return w


# =========================
# 5) text text linear family
# =========================
def pick_best_linear_scaler_by_cv_auc(X_train_raw, y_train, groups,
                                      numeric_features, categorical_features,
                                      candidates=("standard", "minmax", "robust"),
                                      n_splits=5, random_state=42):
    best = None
    best_auc = -np.inf
    report = []

    y_train = np.asarray(y_train).astype(int)
    groups = np.asarray(groups)

    pos = int((y_train == 1).sum())
    neg = int((y_train == 0).sum())
    n_group = int(pd.Series(groups).nunique())

    eff_splits = min(n_splits, pos, neg, n_group)
    if eff_splits < 2:
        raise ValueError(
            f"text text group-aware CV "
            f"pos={pos}, neg={neg}, n_group={n_group}, requested={n_splits}"
        )

    if HAS_STRATIFIED_GROUP_KFOLD:
        cv = StratifiedGroupKFold(
            n_splits=eff_splits,
            shuffle=True,
            random_state=random_state
        )
        cv_name = "StratifiedGroupKFold"
    else:
        cv = GroupKFold(n_splits=eff_splits)
        cv_name = "GroupKFold"

    print(f"[linear auto scaler] text {cv_name}, n_splits={eff_splits}")

    for mode in candidates:
        fold_auc_list = []
        fold_ap_list = []

        for tr_idx, va_idx in cv.split(X_train_raw, y_train, groups):
            Xtr_raw = X_train_raw.iloc[tr_idx].copy()
            Xva_raw = X_train_raw.iloc[va_idx].copy()
            ytr = y_train[tr_idx]
            yva = y_train[va_idx]

            pre = build_preprocessor(
                numeric_features=numeric_features,
                categorical_features=categorical_features,
                scaler_mode=mode
            )
            Xtr = pre.fit_transform(Xtr_raw)
            Xva = pre.transform(Xva_raw)

            lr = LogisticRegression(max_iter=3000, class_weight="balanced")
            lr.fit(Xtr, ytr)
            p = lr.predict_proba(Xva)[:, 1]

            try:
                auc = roc_auc_score(yva, p)
            except Exception:
                auc = np.nan
            try:
                ap = average_precision_score(yva, p)
            except Exception:
                ap = np.nan

            fold_auc_list.append(auc)
            fold_ap_list.append(ap)

        mean_auc = np.nanmean(fold_auc_list)
        mean_ap = np.nanmean(fold_ap_list)
        report.append((mode, mean_auc, mean_ap))

        if np.isfinite(mean_auc) and mean_auc > best_auc:
            best_auc = mean_auc
            best = mode

    rep_df = pd.DataFrame(
        report, columns=["scaler", "cv_auc", "cv_ap"]
    ).sort_values("cv_auc", ascending=False)

    return best, rep_df


