# 6) text text
# =========================
def threshold_sensitivity_report(df_train, target_col, q_list):
    target = pd.to_numeric(df_train[target_col], errors="coerce")
    out = []
    for q in q_list:
        thr_q = float(target.quantile(q))
        y_q = (target >= thr_q).astype(int)
        out.append({
            "quantile": q,
            "threshold": thr_q,
            "n_train": int(len(y_q)),
            "n_positive": int(y_q.sum()),
            "positive_rate": float(y_q.mean())
        })
    return pd.DataFrame(out)


# =========================
# 7) CV splitter text
# =========================
def build_cv_splitter(y, groups, n_splits=5, random_state=42):
    y = np.asarray(y).astype(int)
    groups = np.asarray(groups)

    pos = int((y == 1).sum())
    neg = int((y == 0).sum())
    n_group = int(pd.Series(groups).nunique())

    eff_splits = min(n_splits, pos, neg, n_group)

    if eff_splits < 2:
        raise ValueError(
            f"text text group-aware CV "
            f"pos={pos}, neg={neg}, n_group={n_group}, requested={n_splits}"
        )

    if eff_splits != n_splits:
        print(
            f"[text] CV folds text {n_splits} text {eff_splits} "
            f"(pos={pos}, neg={neg}, n_group={n_group})"
        )

    if HAS_STRATIFIED_GROUP_KFOLD:
        splitter = StratifiedGroupKFold(
            n_splits=eff_splits,
            shuffle=True,
            random_state=random_state
        )
    else:
        splitter = GroupKFold(n_splits=eff_splits)

    return splitter


