def _safe_float_or_none(x):
    try:
        if pd.isna(x):
            return None
        return float(x)
    except Exception:
        return None

def build_range_summary(df_obj, variables):
    rows = []
    for var in variables:
        if var not in df_obj.columns:
            continue
        s = pd.to_numeric(df_obj[var], errors="coerce").replace([np.inf, -np.inf], np.nan)
        rows.append({
            "variable": var,
            "n_non_missing": int(s.notna().sum()),
            "min": _safe_float_or_none(s.min()),
            "max": _safe_float_or_none(s.max())
        })
    return pd.DataFrame(rows)

def build_category_levels_summary(df_obj, categorical_vars):
    out = {}
    for var in categorical_vars:
        if var not in df_obj.columns:
            continue
        vals = (
            df_obj[var]
            .astype(str)
            .replace("nan", np.nan)
            .dropna()
            .astype(str)
            .str.strip()
        )
        levels = sorted(vals.unique().tolist())
        out[var] = {
            "n_levels": int(len(levels)),
            "levels": levels
        }
    return out


