def _resolve_base_df():
    if "df" in globals() and isinstance(globals()["df"], pd.DataFrame):
        return globals()["df"].copy()

    has_train = "df_train" in globals() and isinstance(globals()["df_train"], pd.DataFrame)
    has_test = "df_test" in globals() and isinstance(globals()["df_test"], pd.DataFrame)

    if has_train and has_test:
        return pd.concat(
            [globals()["df_train"].copy(), globals()["df_test"].copy()],
            axis=0,
            ignore_index=True
        )

    raise ValueError("text df text df_train / df_test text ")


def _resolve_target_de():
    if "TARGET_DE" in globals():
        return globals()["TARGET_DE"]
    return "DE_tumor"


def _resolve_save_dir():
    if "SAVE_DIR" in globals():
        return globals()["SAVE_DIR"]
    return str(RESULTS_DIR / "model_outputs")


def _resolve_thr(df_, target_de_):
    if "thr" in globals():
        return float(globals()["thr"])

    if "df_train" in globals() and isinstance(globals()["df_train"], pd.DataFrame):
        if target_de_ in globals()["df_train"].columns:
            s = pd.to_numeric(globals()["df_train"][target_de_], errors="coerce").dropna()
            if len(s) > 0:
                return float(s.quantile(0.75))

    if target_de_ in df_.columns:
        s = pd.to_numeric(df_[target_de_], errors="coerce").dropna()
        if len(s) > 0:
            return float(s.quantile(0.75))

    raise ValueError(f"text thr text {target_de_} ")


df_eda_source = _resolve_base_df()
TARGET_DE = _resolve_target_de()
SAVE_DIR = _resolve_save_dir()
thr = _resolve_thr(df_eda_source, TARGET_DE)


