def make_safe_filename(s):
    s = str(s).strip()
    s = re.sub(r'[\\/:*figure"<>|]', "_", s)
    s = s.replace(" ", "_")
    return s

def save_and_show(fig, out_path_wo_ext, show=True):
    fig.savefig(out_path_wo_ext + ".png", dpi=600, bbox_inches="tight", facecolor="white")
    fig.savefig(out_path_wo_ext + ".svg", bbox_inches="tight", facecolor="white")
    if show:
        plt.show()
    plt.close(fig)

def _get_existing_cols(df_, cols):
    return [c for c in cols if c in df_.columns]

def _smart_wrap(s, width=18):
    s = str(s).replace("_", " ")
    return textwrap.fill(s, width=width, break_long_words=False, break_on_hyphens=False)

def _pretty_label(col):
    pretty_map = {
        "Type": "Type",
        "MAT": "MAT",
        "TS": "TS",
        "CT": "CT",
        "TM": "TM",
        "Shape": "Shape",
        "Size": "Size\n(log10(nm))",
        "Size_nm": "Size\n(nm)",
        "Zeta Potential": "Zeta\nPotential",
        "Admin": "Admin",
        "y": "y",
        "DE_tumor": "DE_\ntumor",
    }
    return pretty_map.get(col, col)

def _pretty_axis_label(col):
    axis_map = {
        "Type": "Type",
        "MAT": "MAT",
        "TS": "TS",
        "CT": "CT",
        "TM": "TM",
        "Shape": "Shape",
        "Size": "Size",
        "Size_nm": "Size_nm",
        "Zeta Potential": "Zeta Potential",
        "Admin": "Admin",
        "y": "y",
        "DE_tumor": "DE_tumor",
    }
    return axis_map.get(col, col)

def _bold_axes(ax, title=None, xlabel=None, ylabel=None, tick_bold=True):
    if title is not None:
        ax.set_title(title, fontsize=16, fontweight="bold")
    if xlabel is not None:
        ax.set_xlabel(xlabel, fontsize=13, fontweight="bold")
    if ylabel is not None:
        ax.set_ylabel(ylabel, fontsize=13, fontweight="bold")
    if tick_bold:
        for lab in ax.get_xticklabels():
            lab.set_fontweight("bold")
            lab.set_fontstyle("normal")
        for lab in ax.get_yticklabels():
            lab.set_fontweight("bold")
            lab.set_fontstyle("normal")

def _quantile_ylim(series, q_low, q_high):
    x = pd.to_numeric(series, errors="coerce").replace([np.inf, -np.inf], np.nan).dropna()
    if x.empty:
        return None
    lo = x.quantile(q_low)
    hi = x.quantile(q_high)
    if not np.isfinite(lo) or not np.isfinite(hi) or hi <= lo:
        return None
    pad = (hi - lo) * 0.05
    return (lo - pad, hi + pad)

def _apply_ylim_by_rule(ax, series, feature_name):
    rule = YLIM_RULES.get(feature_name, {"mode": "auto"})
    mode = rule.get("mode", "auto")

    if mode == "auto":
        return
    elif mode == "manual":
        ylim = rule.get("ylim", None)
        if ylim is not None:
            ax.set_ylim(ylim[0], ylim[1])
    elif mode == "q":
        q_low = rule.get("q_low", 0.01)
        q_high = rule.get("q_high", 0.99)
        yl = _quantile_ylim(series, q_low, q_high)
        if yl is not None:
            ax.set_ylim(yl[0], yl[1])
    else:
        raise ValueError(f"text ylim rule mode: {mode}")


def _normalize_eda_cat_series(s, col=None):
    s = s.copy()
    na_mask = s.isna()
    s = s.astype(str)
    s = s.str.replace(" ", " ", regex=False)
    s = s.str.replace(r"\s+", " ", regex=True)
    s = s.str.strip()

    if col == "CT":
        s = s.str.replace(r"^\s*cervix\s*$", "Cervix", regex=True, flags=re.IGNORECASE)

    s = s.str.replace(r"^\s*othersfigure\s*$", "Other", regex=True, flags=re.IGNORECASE)
    s.loc[na_mask] = np.nan
    return s


def normalize_eda_categorical_df(df_, cat_cols):
    df_ = df_.copy()
    for c in cat_cols:
        if c in df_.columns:
            df_[c] = _normalize_eda_cat_series(df_[c], col=c)
    return df_

def _merge_tail_counts(vc, topk=12, others_name="Other"):
    vc = vc.sort_values(ascending=False)
    if len(vc) <= topk:
        return vc
    head = vc.iloc[:topk].copy()
    tail_sum = vc.iloc[topk:].sum()
    if others_name in head.index:
        head.loc[others_name] = head.loc[others_name] + tail_sum
    else:
        head.loc[others_name] = tail_sum
    return head

def _format_count_pct(values):
    total = np.sum(values)
    if total <= 0:
        return [str(int(v)) for v in values]
    return [f"{int(v)} ({v/total:.1%})" for v in values]

def _barh_style_params(n_cat):
    if n_cat <= 3:
        return {"fig_h": 2.5, "bar_h": 0.28, "wrap_width": 24, "label_fontsize": 10.5}
    elif n_cat <= 5:
        return {"fig_h": 3.1, "bar_h": 0.30, "wrap_width": 22, "label_fontsize": 10.3}
    elif n_cat <= 8:
        return {"fig_h": 4.1, "bar_h": 0.34, "wrap_width": 20, "label_fontsize": 10.0}
    elif n_cat <= 12:
        return {"fig_h": 5.0, "bar_h": 0.38, "wrap_width": 20, "label_fontsize": 9.8}
    else:
        return {"fig_h": min(7.2, 0.36 * n_cat + 1.0), "bar_h": 0.42, "wrap_width": 18, "label_fontsize": 9.5}

def _make_barh_labels(index_values, wrap_width):
    labels = []
    for x in index_values:
        sx = str(x).strip()
        if len(sx) <= 14:
            labels.append(sx)
            continue
        if " " not in sx and "-" not in sx and "_" not in sx and "/" not in sx:
            labels.append(sx)
            continue
        labels.append(_smart_wrap(sx, width=wrap_width))
    return labels


