def plot_box_overall_combined_longform(df_, cols, out_dir, show=True):
    cols = _get_existing_cols(df_, cols)
    if not cols:
        return

    dd = df_[cols].copy()
    for c in cols:
        dd[c] = pd.to_numeric(dd[c], errors="coerce")
    dd_long = dd.melt(var_name="feature", value_name="value").dropna()
    if dd_long.empty:
        return

    dd_long["feature_pretty"] = dd_long["feature"].map(_pretty_axis_label)
    order = [_pretty_axis_label(c) for c in cols]
    dd_long["feature_pretty"] = pd.Categorical(dd_long["feature_pretty"], categories=order, ordered=True)

    fig, ax = plt.subplots(figsize=(11.8, 6.0))
    sns.boxplot(data=dd_long, x="feature_pretty", y="value", order=order, ax=ax)

    plt.setp(ax.get_xticklabels(), rotation=15, ha="center", fontstyle="normal")
    _bold_axes(ax, title="Numeric", xlabel="Features", ylabel="Values")
    ax.grid(True, axis="y", linestyle="--", linewidth=0.5, alpha=0.30)
    ax.spines["top"].set_visible(False)
    ax.spines["right"].set_visible(False)

    yl = _quantile_ylim(dd_long["value"], 0.01, 0.99)
    if yl is not None:
        ax.set_ylim(yl[0], yl[1])

    save_and_show(fig, os.path.join(out_dir, "boxplot_overall_numeric_combined"), show=show)

