def plot_box_by_group(df_, numeric_cols, group_col, out_dir,
                      show=True, top_k=12, max_categories_hard=30, palette="Set3"):
    numeric_cols = _get_existing_cols(df_, numeric_cols)
    if (group_col not in df_.columns) or (len(numeric_cols) == 0):
        return

    g = df_[group_col].fillna("<NA>").astype(str)
    vc = g.value_counts()
    if len(vc) > max_categories_hard:
        return

    keep_cats = vc.head(top_k).index.tolist()
    dsub = df_.copy()
    dsub[group_col] = dsub[group_col].fillna("<NA>").astype(str)
    dsub = dsub[dsub[group_col].isin(keep_cats)].copy()
    if dsub.empty:
        return

    order = keep_cats

    for col in numeric_cols:
        dd = dsub[[group_col, col]].copy()
        dd[col] = pd.to_numeric(dd[col], errors="coerce")
        dd = dd.dropna(subset=[col])
        if dd.empty:
            continue

        fig, ax = plt.subplots(figsize=(13.0, 6.8))
        sns.boxplot(
            x=group_col, y=col, data=dd,
            order=order,
            hue=group_col,
            palette=palette,
            dodge=False,
            legend=False,
            ax=ax
        )

        _bold_axes(
            ax,
            title=f"{col} by {group_col}",
            xlabel=group_col,
            ylabel=_pretty_axis_label(col)
        )

        plt.setp(ax.get_xticklabels(), rotation=25, ha="right", fontstyle="normal")
        ax.grid(True, axis="y", linestyle="--", linewidth=0.5, alpha=0.30)
        ax.spines["top"].set_visible(False)
        ax.spines["right"].set_visible(False)

        _apply_ylim_by_rule(ax, dd[col], col)

        save_and_show(
            fig,
            os.path.join(out_dir, f"box_{make_safe_filename(col)}_by_{make_safe_filename(group_col)}"),
            show=show
        )

