def encode_categoricals_for_corr(df_, cat_cols):
    d = df_.copy()
    for c in cat_cols:
        if c in d.columns:
            d[c] = LabelEncoder().fit_transform(d[c].fillna("<NA>").astype(str))
    return d

def plot_feature_vs_target_corr_heatmap(
    df_, features, target,
    method, out_dir, filename, title,
    show=True,
    left_margin=0.30,
    ytick_rotation=0,
    ytick_labelsize=12
):
    features = _get_existing_cols(df_, features)
    if (target not in df_.columns) or (len(features) == 0):
        return

    dd = df_[features + [target]].copy()
    for c in features + [target]:
        dd[c] = pd.to_numeric(dd[c], errors="coerce")
    dd = dd.dropna()
    if dd.empty:
        return

    corr_col = dd.corr(method=method)[[target]].drop(index=[target])
    corr_col = corr_col.reindex(corr_col[target].abs().sort_values(ascending=False).index)
    corr_col.index = [_pretty_label(i) for i in corr_col.index.tolist()]

    fig_h = max(3.2, 0.55 * len(corr_col))
    fig, ax = plt.subplots(figsize=(7.8, fig_h))

    sns.heatmap(
        corr_col,
        annot=True, fmt=".2f",
        vmin=-1, vmax=1, cmap="coolwarm",
        linewidths=0.6, linecolor="white",
        cbar=True, ax=ax,
        xticklabels=[_pretty_label(target)],
        yticklabels=corr_col.index.tolist()
    )

    _bold_axes(ax, title=title, xlabel="", ylabel="")
    ax.tick_params(axis="y", rotation=ytick_rotation, labelsize=ytick_labelsize, pad=6)
    for t in ax.get_yticklabels():
        t.set_horizontalalignment("right")
        t.set_fontstyle("normal")
    ax.tick_params(axis="x", rotation=0, labelsize=12, pad=6)
    plt.setp(ax.get_xticklabels(), fontstyle="normal")

    fig.subplots_adjust(left=left_margin, right=0.95, top=0.90, bottom=0.10)

    save_and_show(fig, os.path.join(out_dir, filename), show=show)

def plot_full_corr_matrix(
    df_encoded, cols, target,
    out_dir, filename, title,
    method="pearson", show=True,
    left_margin=0.28,
    bottom_margin=0.36
):
    cols = _get_existing_cols(df_encoded, cols)
    if (target not in cols) or (len(cols) <= 1):
        return

    dd = df_encoded[cols].copy()
    for c in cols:
        dd[c] = pd.to_numeric(dd[c], errors="coerce")
    dd = dd.dropna()
    if dd.empty:
        return

    corr = dd.corr(method=method)

    order = corr[target].drop(labels=[target]).abs().sort_values(ascending=False).index.tolist()
    ordered_cols = order + [target]
    corr = corr.loc[ordered_cols, ordered_cols]

    xlabels = [_pretty_label(c) for c in corr.columns]
    ylabels = [_pretty_label(c) for c in corr.index]

    n = len(ordered_cols)
    fig_w = max(10, 0.90 * n)
    fig_h = max(7, 0.72 * n)

    fig, ax = plt.subplots(figsize=(fig_w, fig_h))
    sns.heatmap(
        corr,
        annot=True, fmt=".2f",
        vmin=-1, vmax=1, cmap="coolwarm",
        linewidths=0.5, linecolor="white",
        cbar=True, ax=ax,
        xticklabels=xlabels, yticklabels=ylabels,
        cbar_kws={"shrink": 0.85, "pad": 0.02}
    )

    _bold_axes(ax, title=title, xlabel="", ylabel="")
    ax.tick_params(axis="x", rotation=0, labelsize=10, pad=8)
    ax.tick_params(axis="y", rotation=0, labelsize=10)

    plt.setp(ax.get_xticklabels(), ha="center", va="top", fontstyle="normal", rotation=0)
    plt.setp(ax.get_yticklabels(), fontstyle="normal")

    fig.subplots_adjust(left=left_margin, right=0.98, bottom=bottom_margin, top=0.93)

    save_and_show(fig, os.path.join(out_dir, filename), show=show)

cat_cols_use = _get_existing_cols(df_eda, CATEGORICAL_COLS)
