def strip_column_names(df):
    df = df.copy()
    df.columns = [c.strip() if isinstance(c, str) else c for c in df.columns]
    return df


def normalize_name_for_match(x):
    """
    text
    DE_tumor / DETumor / DE tumor / DE-tumor text
    """
    x = str(x).strip().lower()
    x = re.sub(r"[\s_\-()]+", "", x)
    return x


def find_target_column(df, preferred="DE_tumor"):
    """
    text
    text exact match text
    """
    cols = list(df.columns)

    if preferred in cols:
        return preferred

    aliases = [
        preferred,
        "DE_tumor",
        "DETumor",
        "DE tumor",
        "DE-tumor",
        "DE_Tumor",
        "DEtumor",
        "DE Tumor",
    ]

    for a in aliases:
        if a in cols:
            return a

    target_norms = {normalize_name_for_match(x) for x in aliases}

    for c in cols:
        if normalize_name_for_match(c) in target_norms:
            return c

    for c in cols:
        cc = str(c).lower()
        if ("de" in cc) and ("tumor" in cc):
            return c

    return None


def canonicalize_target_column(df, preferred="DE_tumor"):
    """
    text preferred
    """
    df = strip_column_names(df)
    target_col = find_target_column(df, preferred=preferred)

    if target_col is None:
        return df, None

    if target_col != preferred:
        df = df.rename(columns={target_col: preferred})

    return df, preferred


def get_existing_cols(df, cols):
    return [c for c in cols if c in df.columns]


def report_candidate_df(name, df):
    df_tmp, target_col = canonicalize_target_column(df, preferred=TARGET_DE)

    feature_hits = get_existing_cols(
        df_tmp,
        NUMERIC_COLS_BASE + CATEGORICAL_COLS + ["Size_nm"]
    )

    has_target = target_col is not None and target_col in df_tmp.columns

    return {
        "name": name,
        "shape": df_tmp.shape,
        "has_target": has_target,
        "target_col": target_col,
        "feature_hits": feature_hits,
        "n_feature_hits": len(feature_hits),
        "columns": list(df_tmp.columns)
    }


