def resolve_base_df_fixed():
    """
    text
    text df_enc
    text df_enc text text
    """

    candidates = []

    if "df_eda" in globals() and isinstance(globals()["df_eda"], pd.DataFrame):
        candidates.append(("df_eda", globals()["df_eda"].copy()))

    if "df" in globals() and isinstance(globals()["df"], pd.DataFrame):
        candidates.append(("df", globals()["df"].copy()))

    has_train = "df_train" in globals() and isinstance(globals()["df_train"], pd.DataFrame)
    has_test = "df_test" in globals() and isinstance(globals()["df_test"], pd.DataFrame)

    if has_train and has_test:
        df_all = pd.concat(
            [globals()["df_train"].copy(), globals()["df_test"].copy()],
            axis=0,
            ignore_index=True
        )
        candidates.append(("df_train + df_test", df_all))

    has_x_train = "X_train_raw" in globals() and isinstance(globals()["X_train_raw"], pd.DataFrame)
    has_x_test = "X_test_raw" in globals() and isinstance(globals()["X_test_raw"], pd.DataFrame)

    if has_x_train and has_x_test and has_train and has_test:
        X_all = pd.concat(
            [globals()["X_train_raw"].copy(), globals()["X_test_raw"].copy()],
            axis=0,
            ignore_index=True
        )

        df_tt = pd.concat(
            [globals()["df_train"].copy(), globals()["df_test"].copy()],
            axis=0,
            ignore_index=True
        )

        df_tt, target_col = canonicalize_target_column(df_tt, preferred=TARGET_DE)

        if target_col is not None and TARGET_DE in df_tt.columns:
            X_all[TARGET_DE] = df_tt[TARGET_DE].to_numpy()
            candidates.append(("X_train_raw + X_test_raw + target", X_all))

    if "df_raw" in globals() and isinstance(globals()["df_raw"], pd.DataFrame):
        candidates.append(("df_raw", globals()["df_raw"].copy()))

    if "df_enc" in globals() and isinstance(globals()["df_enc"], pd.DataFrame):
        candidates.append(("df_enc fallback", globals()["df_enc"].copy()))

    print("\n[Data source diagnosis]")

    if len(candidates) == 0:
        raise ValueError(
            "text DataFrame text text df / df_train / df_test / X_train_raw / X_test_raw "
        )

    diagnostics = []

    for name, df_cand in candidates:
        info = report_candidate_df(name, df_cand)
        diagnostics.append(info)

        print(f"\n- {info['name']}")
        print(f"  shape       : {info['shape']}")
        print(f"  has target  : {info['has_target']}")
        print(f"  target col  : {info['target_col']}")
        print(f"  feature hits: {info['feature_hits']}")

    valid_candidates = [
        item for item in diagnostics
        if item["has_target"] and item["n_feature_hits"] >= 2
    ]

    if len(valid_candidates) == 0:
        print("\n[Available columns in candidates]")

        for info in diagnostics:
            print(f"\n{info['name']}:")
            print(info["columns"])

        raise ValueError(
            "text \n"
            "text text Notebook text kernel \n"
            f"text {TARGET_DE}\n"
            f"text {NUMERIC_COLS_BASE + CATEGORICAL_COLS}"
        )

    chosen_name = valid_candidates[0]["name"]

    for name, df_cand in candidates:
        if name == chosen_name:
            df_out, _ = canonicalize_target_column(df_cand, preferred=TARGET_DE)
            print(f"\n[Selected data source] {chosen_name}")
            print(f"[Selected shape] {df_out.shape}")
            return df_out, chosen_name

    raise RuntimeError("text ")


