def normalize_cat_text(s):
    s = s.astype(str)
    s = s.str.replace("\u00a0", " ", regex=False)
    s = s.str.replace(r"\s+", " ", regex=True)
    s = s.str.strip()
    return s


def normalize_categorical_df(df, cat_cols):
    df = df.copy()

    for c in cat_cols:
        if c in df.columns:
            df[c] = normalize_cat_text(df[c])

    if "CT" in df.columns:
        df["CT"] = df["CT"].astype(str).str.replace(
            r"^\s*cervix\s*$",
            "Cervix",
            regex=True,
            flags=re.IGNORECASE
        )

    for c in cat_cols:
        if c in df.columns:
            df[c] = df[c].astype(str).str.replace(
                r"^\s*othersfigure\s*$",
                "Other",
                regex=True,
                flags=re.IGNORECASE
            )

    return df


def encode_categoricals_for_corr(df, cat_cols):
    df_encoded = df.copy()

    for c in cat_cols:
        if c in df_encoded.columns:
            s = df_encoded[c].fillna("<NA>").astype(str)
            df_encoded[c] = LabelEncoder().fit_transform(s)

    return df_encoded


def add_size_nm_if_needed(df):
    """
    text Size text log10(nm) text Size_nm
    """
    df = df.copy()

    if "Size" in df.columns and "Size_nm" not in df.columns:
        size_num = pd.to_numeric(df["Size"], errors="coerce")

        if size_num.notna().sum() > 0:
            valid = size_num.dropna()

            if len(valid) > 0:
                within_log_range = ((valid >= -1) & (valid <= 6)).mean()

                if within_log_range > 0.8:
                    df["Size_nm"] = 10.0 ** size_num

    return df


def pretty_label(col):
    """
    text
    text
    1. Size text
    2. log10 text 10 text
    3. DE_tumor text tumor text
    """
    if normalize_name_for_match(col) in {
        normalize_name_for_match("DE_tumor"),
        normalize_name_for_match("DETumor"),
        normalize_name_for_match(TARGET_DE),
    }:
        return r"DE$_{\mathrm{tumor}}$"

    pretty_map = {
        "Type": "Type",
        "MAT": "MAT",
        "TS": "TS",
        "CT": "CT",
        "TM": "TM",
        "Shape": "Shape",
        "Size": "Size\n(log$_{10}$(nm))",
        "Size_nm": "Size\n(nm)",
        "Zeta Potential": "Zeta\nPotential",
        "Admin": "Admin",
        "y": "y",
    }

    return pretty_map.get(col, col)


def save_figure_multi_formats(fig, out_dir, base_name):
    """
    text
    - PNG: 900 dpi
    - SVG: text
    - TIFF: 900 dpi
    """
    os.makedirs(out_dir, exist_ok=True)

    png_path = os.path.join(out_dir, f"{base_name}.png")
    svg_path = os.path.join(out_dir, f"{base_name}.svg")
    tiff_path = os.path.join(out_dir, f"{base_name}.tiff")

    fig.savefig(
        png_path,
        dpi=EXPORT_DPI,
        bbox_inches="tight",
        facecolor="white"
    )

    fig.savefig(
        svg_path,
        format="svg",
        bbox_inches="tight",
        facecolor="white"
    )

    fig.savefig(
        tiff_path,
        dpi=EXPORT_DPI,
        format="tiff",
        bbox_inches="tight",
        facecolor="white"
    )

    print(f"[saved] {png_path}")
    print(f"[saved] {svg_path}")
    print(f"[saved] {tiff_path}")


