def plot_full_corr_matrix_single(
    df_encoded,
    cols,
    target="DE_tumor",
    out_dir=OUT_DIR,
    filename="corr_full_matrix_target_no_title_DEtumor_subscript",
    method="pearson",
    left_margin=0.18,
    bottom_margin=0.24,
    show=True
):
    cols = get_existing_cols(df_encoded, cols)

    print("\n[plot columns after filtering]")
    print(cols)

    if target not in cols:
        print("\n[df_encoded columns]")
        print(list(df_encoded.columns))

        raise ValueError(
            f"target={target} text cols text \n"
            f"text cols={cols}\n"
            "text text text full_cols text "
        )

    if len(cols) <= 1:
        raise ValueError(
            f"text text text cols={cols}"
        )

    dd = df_encoded[cols].copy()

    for c in cols:
        dd[c] = pd.to_numeric(dd[c], errors="coerce")

    dd = dd.replace([np.inf, -np.inf], np.nan).dropna()

    if dd.empty:
        raise ValueError(
            "text dropna text text \n"
            "text "
        )

    corr = dd.corr(method=method)

    order = (
        corr[target]
        .drop(labels=[target])
        .abs()
        .sort_values(ascending=False)
        .index
        .tolist()
    )

    ordered_cols = order + [target]
    corr = corr.loc[ordered_cols, ordered_cols]

