draw_singlecol_heatmap(axA, corr_num_de, "Numeric vs DE_tumor")
draw_singlecol_heatmap(axB, corr_cat_de, "Categorical vs DE_tumor")
draw_full_matrix_heatmap(axC, full_corr_de, "Correlation matrix with DE_tumor")

add_panel_label(axA, "A", x=-0.08, y=1.05, fontsize=18)
add_panel_label(axB, "B", x=-0.08, y=1.05, fontsize=18)
add_panel_label(axC, "C", x=-0.03, y=1.04, fontsize=18)

out_base = os.path.join(SUPP_DIR, "Supplementary_Fig_S1_corr_DEtumor_beautified")
