def make_safe_filename(s):
    s = str(s).strip()
    s = re.sub(r'[\\/:*figure"<>|]', "_", s)
    s = s.replace(" ", "_")
    return s

def pretty_label(col):
    mapping = {
        "Size": "Size (log10(nm))",
        "Zeta Potential": "Zeta potential",
        "Admin": "Administration dose",
        "y": "DE label",
        TARGET_DE: TARGET_DE,
    }
    return mapping.get(col, col)

def style_axis(ax):
    ax.grid(True, linestyle="--", linewidth=0.6, alpha=0.26, color="#b0b0b0")
    ax.spines["top"].set_visible(False)
    ax.spines["right"].set_visible(False)
