# 7) text + text
# =========================================================
def build_fold_preprocessor():
    return build_preprocessor(
        numeric_features=numeric_features,
        categorical_features=categorical_features,
        scaler_mode=TREE_SCALER_MODE
    )

def supports_log_loss_criterion():
    try:
        X_tmp = np.array([[0.0], [1.0], [2.0], [3.0]])
        y_tmp = np.array([0, 0, 1, 1])
        clf = DecisionTreeClassifier(criterion="log_loss", random_state=0)
        clf.fit(X_tmp, y_tmp)
        return True
    except Exception:
        return False

SUPPORT_LOG_LOSS = supports_log_loss_criterion()
CRITERION_CANDIDATES = ["gini", "entropy"] + (["log_loss"] if SUPPORT_LOG_LOSS else [])

def build_dt(params, cw_fit):
    criterion = params["criterion"]
    if criterion == "log_loss" and not SUPPORT_LOG_LOSS:
        criterion = "entropy"

    max_depth = params["max_depth"]
    if max_depth is not None:
        max_depth = int(max_depth)

    max_features = params["max_features"]
    if max_features == "none":
        max_features = None

    return DecisionTreeClassifier(
        criterion=criterion,
        splitter=params["splitter"],
        max_depth=max_depth,
        min_samples_split=int(params["min_samples_split"]),
        min_samples_leaf=int(params["min_samples_leaf"]),
        max_features=max_features,
        min_impurity_decrease=float(params["min_impurity_decrease"]),
        ccp_alpha=float(params["ccp_alpha"]),
        class_weight=cw_fit,
        random_state=RANDOM_STATE
    )

def fit_fold_model(Xtr_raw_df, ytr, params):
    pre = build_fold_preprocessor()
    Xtr = pre.fit_transform(Xtr_raw_df)
    Xfit, yfit, cw_fit = apply_imbalance_on_fold(Xtr, ytr)

    model = build_dt(params, cw_fit)
    model.fit(Xfit, yfit)
    return pre, model

def predict_with_fold_model(pre, model, Xraw_df):
    X = pre.transform(Xraw_df)
    return model.predict_proba(X)[:, 1]

# =========================================================
# 8) Optuna text group-aware CV mean PR-AUC
# =========================================================
def objective(trial):
    params = {
        "criterion": trial.suggest_categorical("criterion", CRITERION_CANDIDATES),
        "splitter": trial.suggest_categorical("splitter", ["best", "random"]),
        "max_depth": trial.suggest_categorical(
            "max_depth",
            [None, 3, 4, 5, 6, 8, 10, 12, 15, 20]
        ),
        "min_samples_split": trial.suggest_int("min_samples_split", 2, 30),
        "min_samples_leaf": trial.suggest_int("min_samples_leaf", 1, 20),
        "max_features": trial.suggest_categorical("max_features", ["none", "sqrt", "log2"]),
        "min_impurity_decrease": trial.suggest_float("min_impurity_decrease", 0.0, 0.05),
        "ccp_alpha": trial.suggest_float("ccp_alpha", 1e-6, 1e-1, log=True)
    }

    cv = get_cv_splitter()
    fold_scores = []

    for tr_idx, va_idx in cv.split(X_train_raw, y_train, groups=group_id_train):
        X_tr_raw = X_train_raw.iloc[tr_idx].copy()
        X_va_raw = X_train_raw.iloc[va_idx].copy()
        y_tr = y_train[tr_idx]
        y_va = y_train[va_idx]

        pre, model = fit_fold_model(X_tr_raw, y_tr, params)
        y_prob = predict_with_fold_model(pre, model, X_va_raw)

        score = safe_pr_auc(y_va, y_prob)
        if not np.isfinite(score):
            score = 0.0
        fold_scores.append(score)

    if len(fold_scores) == 0:
        return 0.0
    return float(np.mean(fold_scores))

sampler = optuna.samplers.TPESampler(seed=RANDOM_STATE)
study = optuna.create_study(direction="maximize", sampler=sampler)
study.optimize(objective, n_trials=N_TRIALS, show_progress_bar=False)

best_params = study.best_params
best_cv_pr_auc = float(study.best_value)

print("\n=========================")
