def get_oof_probabilities(best_params):
    cv = get_cv_splitter()
    oof_prob = np.full(len(y_train), np.nan, dtype=float)

    for tr_idx, va_idx in cv.split(X_train_raw, y_train, groups=group_id_train):
        X_tr_raw = X_train_raw.iloc[tr_idx].copy()
        X_va_raw = X_train_raw.iloc[va_idx].copy()
        y_tr = y_train[tr_idx]

        pre, model = fit_fold_model(X_tr_raw, y_tr, best_params)
        oof_prob[va_idx] = predict_with_fold_model(pre, model, X_va_raw)

    if np.isnan(oof_prob).any():
        raise ValueError("OOF text NaN text CV text ")

    return oof_prob

oof_prob_train = get_oof_probabilities(best_params)
