def build_metrics_row(model_name, metrics_dict):
    row = {"model_name": model_name}
    row["PR-AUC"] = metrics_dict.get("PR-AUC", np.nan)
    row["ROC-AUC"] = metrics_dict.get("ROC-AUC", np.nan)
    row["Precision"] = metrics_dict.get("Precision", np.nan)
    row["Recall"] = metrics_dict.get("Recall", np.nan)
    row["F1"] = metrics_dict.get("F1", np.nan)

    first_k = int(RANKING_K_LIST[0]) if len(RANKING_K_LIST) > 0 else 10
    row["Precision@K"] = metrics_dict.get(f"Precision@{first_k}", np.nan)
    row["Recall@K"] = metrics_dict.get(f"Recall@{first_k}", np.nan)
    row["EF@K"] = metrics_dict.get(f"EF@{first_k}", np.nan)
    row["K_used_for_compact_metrics"] = first_k

    row["EF5%"] = metrics_dict.get("EF5%", np.nan)
    row["EF10%"] = metrics_dict.get("EF10%", np.nan)

    return row

