# =========================================================
# 2) text
# =========================================================
def safe_pr_auc(y_true, y_prob):
    y_true = np.asarray(y_true).astype(int)
    y_prob = np.asarray(y_prob, dtype=float)
    if len(y_true) == 0 or len(np.unique(y_true)) < 2:
        return np.nan
    try:
        return float(average_precision_score(y_true, y_prob))
    except Exception:
        return np.nan

def safe_roc_auc(y_true, y_prob):
    y_true = np.asarray(y_true).astype(int)
    y_prob = np.asarray(y_prob, dtype=float)
    if len(y_true) == 0 or len(np.unique(y_true)) < 2:
        return np.nan
    try:
        return float(roc_auc_score(y_true, y_prob))
    except Exception:
        return np.nan

# =========================================================
# 3) text Precision@K / Recall@K / EF@K
#    text EF5% / EF10%
# =========================================================
def ranking_metrics_at_k(y_true, y_prob, k: int):
    y_true = np.asarray(y_true).astype(int)
    y_prob = np.asarray(y_prob, dtype=float)

    n = len(y_true)
    if n == 0:
        return {
            "Precision@K": np.nan,
            "Recall@K": np.nan,
            "EF@K": np.nan,
            "K_eff": 0
        }

    k_eff = int(min(max(k, 1), n))
    order = np.argsort(-y_prob)
    topk_idx = order[:k_eff]

    tp = int(y_true[topk_idx].sum())
    precision_k = tp / float(k_eff)

    pos_total = int(y_true.sum())
    recall_k = tp / float(pos_total) if pos_total > 0 else 0.0

    pos_rate = pos_total / float(n)
    ef_k = (precision_k / pos_rate) if pos_rate > 0 else np.nan

    return {
        "Precision@K": float(precision_k),
        "Recall@K": float(recall_k),
        "EF@K": float(ef_k),
        "K_eff": k_eff
    }

def ef_at_percent(y_true, y_prob, pct: float):
    """
    text EFx% text Precision@x% Recall@x%
    text
        k_eff = ceil(n * pct / 100)
        EFx% = (TP@k_eff / k_eff) / (P / N)
    """
    y_true = np.asarray(y_true).astype(int)
    y_prob = np.asarray(y_prob, dtype=float)

    n = len(y_true)
    if n == 0:
        return {"EF_pct": np.nan, "K_eff_pct": 0}

    k_eff = int(np.ceil(n * float(pct) / 100.0))
    k_eff = int(min(max(k_eff, 1), n))

    order = np.argsort(-y_prob)
    top_idx = order[:k_eff]

    tp = int(y_true[top_idx].sum())
    precision_top = tp / float(k_eff)

    pos_total = int(y_true.sum())
    pos_rate = pos_total / float(n)
    ef_pct = (precision_top / pos_rate) if pos_rate > 0 else np.nan

    return {
        "EF_pct": float(ef_pct),
        "K_eff_pct": k_eff
    }

def eval_ranking_suite(y_true, y_prob, k_list, pct_list):
    out = {
        "PR-AUC": safe_pr_auc(y_true, y_prob),
        "ROC-AUC": safe_roc_auc(y_true, y_prob)
    }

    for k in k_list:
        m = ranking_metrics_at_k(y_true, y_prob, k)
        out[f"Precision@{k}"] = m["Precision@K"]
        out[f"Recall@{k}"] = m["Recall@K"]
        out[f"EF@{k}"] = m["EF@K"]

    for pct in pct_list:
        m_pct = ef_at_percent(y_true, y_prob, pct)
        pct_int = int(pct)
        out[f"EF{pct_int}%"] = m_pct["EF_pct"]

    return out

# =========================================================
# 4) text Precision / Recall / F1
# =========================================================
def pick_threshold_by_f1(y_true, y_prob, grid_size=1001):
    y_true = np.asarray(y_true).astype(int)
    y_prob = np.asarray(y_prob, dtype=float)

    best_thr = 0.5
    best_f1 = -1.0

    thresholds = np.linspace(0.0, 1.0, grid_size)
    for thr in thresholds:
        y_pred = (y_prob >= thr).astype(int)
        f1 = f1_score(y_true, y_pred, zero_division=0)
        if f1 > best_f1:
            best_f1 = f1
            best_thr = float(thr)

    return best_thr, float(best_f1)

def eval_threshold_metrics(y_true, y_prob, thr):
    y_true = np.asarray(y_true).astype(int)
    y_prob = np.asarray(y_prob, dtype=float)
    y_pred = (y_prob >= float(thr)).astype(int)

    return {
        "Precision": float(precision_score(y_true, y_pred, zero_division=0)),
        "Recall": float(recall_score(y_true, y_pred, zero_division=0)),
        "F1": float(f1_score(y_true, y_pred, zero_division=0)),
    }

# =========================================================
# 5) fold text
#    LightGBM text class_weight random_oversample text fold text
# =========================================================
def apply_imbalance_on_fold(X_tr, y_tr):
    X_tr = np.asarray(X_tr)
    y_tr = np.asarray(y_tr).astype(int)

    if IMBALANCE_METHOD_RUN == "none":
        return X_tr, y_tr, None

    if IMBALANCE_METHOD_RUN == "random_oversample":
        X_os, y_os = random_oversample_any(X_tr, y_tr, seed=RANDOM_STATE)
        return np.asarray(X_os), np.asarray(y_os).astype(int), None

    if IMBALANCE_METHOD_RUN == "class_weight":
        if class_weight_dict is None:
            raise ValueError("IMBALANCE_METHOD_RUN='class_weight' text class_weight_dict=None ")
        return X_tr, y_tr, class_weight_dict

    raise ValueError(f"text IMBALANCE_METHOD_RUN: {IMBALANCE_METHOD_RUN}")

# =========================================================
# 6) text CV splitter
# =========================================================
def get_cv_splitter():
    if cv_splitter is not None:
        return cv_splitter
    if "build_cv_splitter" in globals():
        return build_cv_splitter(
            y=y_train,
            groups=group_id_train,
            n_splits=N_SPLITS,
            random_state=RANDOM_STATE
        )
    raise NameError("text cv_splitter text build_cv_splitter text ")

# =========================================================
# 7) text + text
# =========================================================
def build_fold_preprocessor():
    return build_preprocessor(
        numeric_features=numeric_features,
        categorical_features=categorical_features,
        scaler_mode=TREE_SCALER_MODE
    )

def build_lgbm(params, cw_fit):
    params_use = dict(params)
    params_use["class_weight"] = cw_fit
    return LGBMClassifier(
        **params_use,
        objective="binary",
        random_state=RANDOM_STATE,
        n_jobs=-1,
        verbose=-1
    )

def fit_fold_model(Xtr_raw_df, ytr, params):
    pre = build_fold_preprocessor()
    Xtr = pre.fit_transform(Xtr_raw_df)
    Xfit, yfit, cw_fit = apply_imbalance_on_fold(Xtr, ytr)

    model = build_lgbm(params, cw_fit)
    model.fit(Xfit, yfit)
    return pre, model

def predict_with_fold_model(pre, model, Xraw_df):
    X = pre.transform(Xraw_df)
    return model.predict_proba(X)[:, 1]

# =========================================================
# 8) Optuna text group-aware CV mean PR-AUC
# =========================================================
def objective(trial):
    params = {
        "n_estimators": trial.suggest_int("n_estimators", 100, 1000, step=50),
        "learning_rate": trial.suggest_float("learning_rate", 1e-3, 0.2, log=True),
        "num_leaves": trial.suggest_int("num_leaves", 15, 127),
        "max_depth": trial.suggest_int("max_depth", -1, 20),
        "min_child_samples": trial.suggest_int("min_child_samples", 5, 50),
        "subsample": trial.suggest_float("subsample", 0.7, 1.0),
        "colsample_bytree": trial.suggest_float("colsample_bytree", 0.7, 1.0),
        "reg_alpha": trial.suggest_float("reg_alpha", 0.0, 2.0),
        "reg_lambda": trial.suggest_float("reg_lambda", 0.0, 2.0),
    }

    cv = get_cv_splitter()
    fold_scores = []

    for tr_idx, va_idx in cv.split(X_train_raw, y_train, groups=group_id_train):
        X_tr_raw = X_train_raw.iloc[tr_idx].copy()
        X_va_raw = X_train_raw.iloc[va_idx].copy()
        y_tr = y_train[tr_idx]
        y_va = y_train[va_idx]

        pre, model = fit_fold_model(X_tr_raw, y_tr, params)
        y_prob = predict_with_fold_model(pre, model, X_va_raw)

        score = safe_pr_auc(y_va, y_prob)
        if not np.isfinite(score):
            score = 0.0
        fold_scores.append(score)

    if len(fold_scores) == 0:
        return 0.0
    return float(np.mean(fold_scores))

sampler = optuna.samplers.TPESampler(seed=RANDOM_STATE)
study = optuna.create_study(direction="maximize", sampler=sampler)
study.optimize(objective, n_trials=N_TRIALS, show_progress_bar=False)

best_params = study.best_params.copy()
best_cv_pr_auc = float(study.best_value)

print("\n=========================")
print("Optuna text")
print("best CV PR-AUC =", best_cv_pr_auc)
print("best params    =", best_params)
print("=========================\n")

