# =========================================================
def cross_validate_full_metrics(best_params, thr_for_eval, k_list, pct_list):
    cv = get_cv_splitter()
    fold_rows = []

    for fold_id, (tr_idx, va_idx) in enumerate(
        cv.split(X_train_raw, y_train, groups=group_id_train), start=1
    ):
        X_tr_raw = X_train_raw.iloc[tr_idx].copy()
        X_va_raw = X_train_raw.iloc[va_idx].copy()
        y_tr = y_train[tr_idx]
        y_va = y_train[va_idx]

        pre, model = fit_fold_model(X_tr_raw, y_tr, best_params)
        y_prob = predict_with_fold_model(pre, model, X_va_raw)

        rank_metrics = eval_ranking_suite(y_va, y_prob, k_list, pct_list)
        thr_metrics = eval_threshold_metrics(y_va, y_prob, thr_for_eval)

        row = {"fold": fold_id}
        row.update(rank_metrics)
        row.update(thr_metrics)
        fold_rows.append(row)

    fold_df = pd.DataFrame(fold_rows)

    summary = {}
    metric_cols = [c for c in fold_df.columns if c != "fold"]
    for c in metric_cols:
        arr = pd.to_numeric(fold_df[c], errors="coerce").to_numpy(dtype=float)
        summary[c] = {
            "mean": float(np.nanmean(arr)) if len(arr) > 0 else np.nan,
            "std": float(np.nanstd(arr, ddof=1)) if np.sum(~np.isnan(arr)) > 1 else 0.0
        }

    return fold_df, summary

cv_fold_df, cv_summary = cross_validate_full_metrics(
    best_params=best_params,
    thr_for_eval=best_thr,
    k_list=RANKING_K_LIST,
    pct_list=PERCENT_CUTOFF_LIST
)

