test_rank_metrics = eval_ranking_suite(y_test, test_prob, RANKING_K_LIST, PERCENT_CUTOFF_LIST)
test_thr_metrics = eval_threshold_metrics(y_test, test_prob, best_thr)

oof_metrics_all = {}
oof_metrics_all.update(oof_rank_metrics)
