def _assert_two_classes(y, name="y"):
    uniq = np.unique(np.asarray(y))
    if len(uniq) != 2:
        raise ValueError(f"{name} text text={uniq} ")

def _assert_no_nan_inf(X, name="X"):
    arr = np.asarray(X, dtype=float)
    if np.isnan(arr).any():
        raise ValueError(f"{name} text NaN")
    if np.isinf(arr).any():
        raise ValueError(f"{name} text Inf")

_assert_two_classes(y_train, "y_train")
