def load_payload_from_memory_or_file(short_name):
    var_name = MODEL_VAR_MAP.get(short_name, None)
    if var_name is not None and var_name in globals():
        obj = globals()[var_name]
        if isinstance(obj, dict):
            return obj, f"memory:{var_name}"

    file_path = MODEL_FILE_MAP.get(short_name, None)
    if file_path is not None and os.path.exists(file_path):
        obj = joblib.load(file_path)
        if isinstance(obj, dict):
            return obj, f"file:{file_path}"

    return None, None

def extract_meta_probs(payload, short_name):
    if not isinstance(payload, dict):
        raise ValueError(f"{short_name} payload text dict ")

    if "oof_prob_train" not in payload:
        raise ValueError(f"{short_name} payload text oof_prob_train ")
    if "test_prob" not in payload:
        raise ValueError(f"{short_name} payload text test_prob ")

    oof_prob = np.asarray(payload["oof_prob_train"], dtype=float).reshape(-1)
    test_prob = np.asarray(payload["test_prob"], dtype=float).reshape(-1)

    if len(oof_prob) != len(y_train):
        raise ValueError(
            f"{short_name} text oof_prob_train text={len(oof_prob)} "
            f"text y_train text={len(y_train)} "
        )
    if len(test_prob) != len(y_test):
        raise ValueError(
            f"{short_name} text test_prob text={len(test_prob)} "
            f"text y_test text={len(y_test)} "
        )

    if np.isnan(oof_prob).any() or np.isinf(oof_prob).any():
        raise ValueError(f"{short_name} text oof_prob_train text NaN/Inf ")
    if np.isnan(test_prob).any() or np.isinf(test_prob).any():
        raise ValueError(f"{short_name} text test_prob text NaN/Inf ")

    return oof_prob, test_prob

