# =========================================================
def cross_validate_full_metrics_from_oof(y, oof_prob, thr_for_eval, k_list, pct_list):
    y = np.asarray(y).astype(int)
    oof_prob = np.asarray(oof_prob, dtype=float)

    cv = get_cv_splitter()
    fold_rows = []

    for fold_id, (_, va_idx) in enumerate(
        cv.split(np.zeros(len(y)), y, groups=group_id_train), start=1
    ):
        y_va = y[va_idx]
        p_va = oof_prob[va_idx]

        rank_metrics = eval_ranking_suite(y_va, p_va, k_list, pct_list)
        thr_metrics = eval_threshold_metrics(y_va, p_va, thr_for_eval)

        row = {"fold": fold_id}
        row.update(rank_metrics)
        row.update(thr_metrics)
        fold_rows.append(row)

    fold_df = pd.DataFrame(fold_rows)

    summary = {}
    metric_cols = [c for c in fold_df.columns if c != "fold"]
    for c in metric_cols:
        arr = pd.to_numeric(fold_df[c], errors="coerce").to_numpy(dtype=float)
        summary[c] = {
            "mean": float(np.nanmean(arr)) if len(arr) > 0 else np.nan,
            "std": float(np.nanstd(arr, ddof=1)) if np.sum(~np.isnan(arr)) > 1 else 0.0
        }

    return fold_df, summary

