def load_payload(model_var_name):
    """
    text text text SAVE_DIR/<model_var_name>.joblib text
    """
    if model_var_name in globals() and globals()[model_var_name] is not None:
        obj = globals()[model_var_name]
        if isinstance(obj, dict):
            return obj, f"memory:{model_var_name}"

    file_path = os.path.join(SAVE_DIR, f"{model_var_name}.joblib")
    if os.path.exists(file_path):
        obj = joblib.load(file_path)
        if isinstance(obj, dict):
            return obj, f"file:{file_path}"

    return None, None


def safe_float(x):
    try:
        if x is None:
            return np.nan
        return float(x)
    except Exception:
        return np.nan


# =========================================================
# 4) text
# =========================================================
def extract_metrics_row(model_name, payload, split="test", k_list=(5, 10, 20), pct_list=(5, 10)):
    """
    text payload text split text
    text
      - text / text PR-AUC, ROC-AUC, Precision@K, Recall@K, EF@K, EFx%
      - text Precision, Recall, F1 text text
    """
    if not isinstance(payload, dict):
        return None

    metrics_key = f"{split}_metrics"
    metrics = payload.get(metrics_key, None)
    if not isinstance(metrics, dict):
        return None

    row = {
        "model_name": payload.get("model_name", model_name),
        "PR-AUC": safe_float(metrics.get("PR-AUC", np.nan)),
        "ROC-AUC": safe_float(metrics.get("ROC-AUC", np.nan)),
        "Precision": safe_float(metrics.get("Precision", np.nan)),
        "Recall": safe_float(metrics.get("Recall", np.nan)),
        "F1": safe_float(metrics.get("F1", np.nan)),
    }

    for k in k_list:
        row[f"Precision@{k}"] = safe_float(metrics.get(f"Precision@{k}", np.nan))
        row[f"Recall@{k}"] = safe_float(metrics.get(f"Recall@{k}", np.nan))
        row[f"EF@{k}"] = safe_float(metrics.get(f"EF@{k}", np.nan))

    for pct in pct_list:
        pct_int = int(pct)
        row[f"EF{pct_int}%"] = safe_float(metrics.get(f"EF{pct_int}%", np.nan))

    return row


