def sort_summary_df_for_selection(df, k_list=(5, 10, 20), pct_list=(5, 10)):
    """
    text text OOF text
      1) PR-AUC
      2) EF@textK
      3) Precision@textK
      4) Recall@textK
      5) EFtext
      6) ROC-AUC

    text
      - text / text
      - Precision / Recall / F1 text
    """
    if df.empty:
        return df

    primary_k = int(k_list[0]) if len(k_list) > 0 else 5
    primary_pct = int(pct_list[0]) if len(pct_list) > 0 else 5

    sort_cols = [
        "PR-AUC",
        f"EF@{primary_k}",
        f"Precision@{primary_k}",
        f"Recall@{primary_k}",
        f"EF{primary_pct}%",
        "ROC-AUC",
    ]
    sort_cols = [c for c in sort_cols if c in df.columns]

    return df.sort_values(
        by=sort_cols,
        ascending=[False] * len(sort_cols)
    ).reset_index(drop=True)


def sort_summary_df_for_display(df, k_list=(5, 10, 20), pct_list=(5, 10)):
    """
    text
    text text
    text
      - TEST text
      - text
    """
    return sort_summary_df_for_selection(df, k_list=k_list, pct_list=pct_list)


