from pathlib import Path
import numpy as np
import pandas as pd
import matplotlib as mpl
import matplotlib.pyplot as plt

# =========================
# 0) Path setting
# =========================
if "SAVE_DIR" not in globals():
    SAVE_DIR = str(RESULTS_DIR / "model_outputs")

RUN_DIR = Path(SAVE_DIR).resolve()

FIG3_DIR = RUN_DIR / "output" / "Figure3" / "optimized_single_panels"
SRC_DIR = RUN_DIR / "source_data" / "Figure3" / "optimized_single_panels"

FIG3_DIR.mkdir(parents=True, exist_ok=True)
SRC_DIR.mkdir(parents=True, exist_ok=True)

print("RUN_DIR =", RUN_DIR)
print("Output =", FIG3_DIR)

# =========================
# 1) Global style
# =========================
mpl.rcParams.update({
    "font.family": "sans-serif",
    "font.sans-serif": ["Arial", "Helvetica", "DejaVu Sans", "sans-serif"],
    "svg.fonttype": "none",
    "pdf.fonttype": 42,
    "ps.fonttype": 42,
    "font.size": 8,
    "axes.titlesize": 8.8,
    "axes.labelsize": 8.2,
    "xtick.labelsize": 7.4,
    "ytick.labelsize": 7.6,
    "axes.linewidth": 0.75,
    "xtick.major.width": 0.7,
    "ytick.major.width": 0.7,
    "xtick.major.size": 3.0,
    "ytick.major.size": 3.0,
    "legend.frameon": False,
    "axes.unicode_minus": False,
})

# =========================
# 2) Colors
# =========================
COLOR_PRIMARY = "#3F6FA6"       # CatBoost
COLOR_NEUTRAL = "#BEC6CF"       # other model points
COLOR_ERROR = "#A8B0B8"         # lighter error bars
COLOR_EDGE = "#66717D"
COLOR_TEXT = "#23272B"

# =========================
# 3) Model names and order
# =========================
DISPLAY_NAMES = {
    "best_cat": "CatBoost",
    "best_stacking": "Stacking",
    "best_voting": "Voting",
    "best_svm": "SVM-RBF",
    "best_xgb": "XGBoost",
    "best_lgbm": "LightGBM",
    "best_knn": "KNN",
    "best_lr": "LR",
    "best_dt": "DT",
    "best_dnn": "DNN",
}

ALT_NAMES = {
    "catboost": "CatBoost",
    "cat": "CatBoost",
    "stacking": "Stacking",
    "voting": "Voting",
    "svm-rbf": "SVM-RBF",
    "svm rbf": "SVM-RBF",
    "svm_rbf": "SVM-RBF",
    "xgboost": "XGBoost",
    "xgb": "XGBoost",
    "lightgbm": "LightGBM",
    "lgbm": "LightGBM",
    "knn": "KNN",
    "logistic regression": "LR",
    "logistic_regression": "LR",
    "logistic reg.": "LR",
    "logistic reg": "LR",
    "lr": "LR",
    "decision tree": "DT",
    "decision_tree": "DT",
    "dt": "DT",
    "dnn": "DNN",
}

MODEL_ORDER = [
    "CatBoost",
    "Stacking",
    "Voting",
    "SVM-RBF",
    "XGBoost",
    "LightGBM",
    "KNN",
    "LR",
    "DT",
    "DNN",
]

MODEL_ORDER_MAP = {name: i for i, name in enumerate(MODEL_ORDER)}

def display_name(model_name: str) -> str:
    model_name = str(model_name)

    if model_name in DISPLAY_NAMES:
        return DISPLAY_NAMES[model_name]

    key = (
        model_name
        .lower()
        .replace("best_", "")
        .replace("_", " ")
        .strip()
    )

    if key in ALT_NAMES:
        return ALT_NAMES[key]

    return model_name.replace("best_", "").replace("_", " ").strip()

def remove_top_right_spines(ax):
    ax.spines["top"].set_visible(False)
    ax.spines["right"].set_visible(False)

# =========================
# 4) Read data
# =========================
cv_path = RUN_DIR / "model_summary" / "model_metrics_summary_cv_raw.csv"

if not cv_path.exists():
    raise FileNotFoundError(
        f"text {cv_path}\n"
        "text text model_summary/model_metrics_summary_cv_raw.csv "
    )

df = pd.read_csv(cv_path)

required_cols = ["model_name", "PR-AUC_mean", "PR-AUC_std"]
missing_cols = [c for c in required_cols if c not in df.columns]

if missing_cols:
    raise ValueError(f"model_metrics_summary_cv_raw.csv text {missing_cols}")

# Remove random forest if old output still contains it
rf_like_names = {
    "best_rf",
    "rf",
    "random_forest",
    "random forest",
    "best_random_forest"
}

df = df[
    ~df["model_name"]
    .astype(str)
    .str.lower()
    .isin(rf_like_names)
].copy()

df["display_name"] = df["model_name"].map(display_name)

# Keep only confirmed models and fixed display order
df_plot = df[df["display_name"].isin(MODEL_ORDER)].copy()
df_plot["model_order"] = df_plot["display_name"].map(MODEL_ORDER_MAP)

df_plot = (
    df_plot
    .sort_values("model_order", ascending=True)
    .reset_index(drop=True)
)

if df_plot.empty:
    raise ValueError(
        "df_plot text text model_name text DISPLAY_NAMES / ALT_NAMES text "
    )

# Export source data
df_plot.to_csv(
    SRC_DIR / "Figure3a_classifier_landscape_source_data.csv",
    index=False,
    encoding="utf-8-sig"
)

# =========================
# 5) Plot
# =========================
fig, ax = plt.subplots(figsize=(3.25, 3.05), dpi=300)

y = np.arange(len(df_plot))
is_primary = df_plot["display_name"].eq("CatBoost")

# Error bars: mean ± SD
ax.errorbar(
    df_plot["PR-AUC_mean"],
    y,
    xerr=df_plot["PR-AUC_std"],
    fmt="none",
    ecolor=COLOR_ERROR,
    elinewidth=0.75,
    capsize=2.0,
    capthick=0.75,
    alpha=0.90,
    zorder=1,
)

# Points
ax.scatter(
    df_plot["PR-AUC_mean"],
    y,
    s=np.where(is_primary, 38, 22),
    c=np.where(is_primary, COLOR_PRIMARY, COLOR_NEUTRAL),
    edgecolors=np.where(is_primary, COLOR_PRIMARY, COLOR_EDGE),
    linewidths=0.55,
    zorder=2,
)

# Y axis
ax.set_yticks(y)
ax.set_yticklabels(df_plot["display_name"])
ax.invert_yaxis()
ax.tick_params(axis="y", pad=2)

# X axis range: compact but not cropped
xmin = float((df_plot["PR-AUC_mean"] - df_plot["PR-AUC_std"]).min())
xmax = float((df_plot["PR-AUC_mean"] + df_plot["PR-AUC_std"]).max())

x_left = max(0.20, xmin - 0.025)
x_right = min(1.00, xmax + 0.025)

ax.set_xlim(x_left, x_right)

# Clean rounded ticks
ax.set_xticks(np.arange(0.3, 0.75, 0.1))

# Axis label
ax.set_xlabel("Cross-validation PR-AUC")

# Delete subplot title
ax.set_title("")

# No background grid
ax.grid(False)

remove_top_right_spines(ax)

# Clean remaining spines
ax.spines["left"].set_color(COLOR_TEXT)
ax.spines["bottom"].set_color(COLOR_TEXT)

# No panel label; no in-plot "Primary model" text
plt.tight_layout(pad=0.8)

# =========================
# 6) Export
# =========================
out_base = FIG3_DIR / "Figure3a_classifier_landscape_no_title"

fig.savefig(
    out_base.with_suffix(".png"),
    dpi=900,
    bbox_inches="tight",
    facecolor="white"
)

fig.savefig(
    out_base.with_suffix(".pdf"),
    bbox_inches="tight",
    facecolor="white"
)

fig.savefig(
    out_base.with_suffix(".svg"),
    bbox_inches="tight",
    facecolor="white"
)

fig.savefig(
    out_base.with_suffix(".tiff"),
    dpi=900,
    bbox_inches="tight",
    facecolor="white"
)

plt.show()
plt.close(fig)

print("Figure 3a exported:")
print(out_base.with_suffix(".png"))
print(out_base.with_suffix(".pdf"))
print(out_base.with_suffix(".svg"))
print(out_base.with_suffix(".tiff"))
print("Source data exported:")
print(SRC_DIR / "Figure3a_classifier_landscape_source_data.csv")


