# ------------------------------------------------------------
# 6) Plotting functions
# ------------------------------------------------------------
def plot_confusion_matrix_panel(
    ax,
    counts_df,
    norm_df=None,
    title="",
    show_xlabel=True,
    show_ylabel=True,
    show_xticklabels=True,
    show_yticklabels=True,
    vmax=None,
    show_summary=True,
):
    values = counts_df.to_numpy(dtype=float)

    if vmax is None:
        vmax = np.nanmax(values) if np.nanmax(values) > 0 else 1

    # Matrix layout:
    # [[TN, FP],
    #  [FN, TP]]
    tn = int(values[0, 0])
    fp = int(values[0, 1])
    fn = int(values[1, 0])
    tp = int(values[1, 1])

    ax.imshow(
        values,
        cmap=CMAP_CM,
        vmin=0,
        vmax=vmax * 1.08,
        interpolation="nearest",
    )

    ax.text(
        0.5,
        1.105,
        title,
        transform=ax.transAxes,
        ha="center",
        va="bottom",
        fontsize=7.6,
        fontweight="bold",
        color="#222222",
    )

    if show_summary:
        summary_text = f"(TN: {tn}, FP: {fp}, FN: {fn}, TP: {tp})"
        ax.text(
            0.5,
            1.035,
            summary_text,
            transform=ax.transAxes,
            ha="center",
            va="bottom",
            fontsize=5.8,
            fontweight="normal",
            color="#222222",
        )

    ax.set_xticks([0, 1])
    ax.set_yticks([0, 1])

    if show_xticklabels:
        ax.set_xticklabels(CLASS_TICK_LABELS, fontsize=6.5)
    else:
        ax.set_xticklabels([])

    if show_yticklabels:
        ax.set_yticklabels(CLASS_TICK_LABELS, fontsize=6.5)
    else:
        ax.set_yticklabels([])

    if show_xlabel:
        ax.set_xlabel("Predicted label", fontsize=6.7, labelpad=1.6)
    else:
        ax.set_xlabel("")

    if show_ylabel:
        ax.set_ylabel("True label", fontsize=6.7, labelpad=1.8)
    else:
        ax.set_ylabel("")

    for i in range(2):
        for j in range(2):
            count = int(values[i, j])
            color = "white" if values[i, j] > 0.55 * vmax else "#222222"

            ax.text(
                j,
                i,
                f"{count}",
                ha="center",
                va="center",
                fontsize=8.6,
                fontweight="bold" if values[i, j] > 0.55 * vmax else "normal",
                color=color,
            )

    for spine in ax.spines.values():
        spine.set_visible(False)

    ax.tick_params(length=0, pad=1.8)


def panel_fold_cm(
    ax,
    fold_id,
    show_xlabel=True,
    show_ylabel=True,
    show_xticklabels=True,
    show_yticklabels=True,
):
    if fold_id not in fold_cm_counts:
        raise ValueError(
            f"Fold {fold_id} not found. Existing folds: {list(fold_cm_counts.keys())}"
        )

    max_fold_value = max(
        fold_cm_counts[k].to_numpy().max()
        for k in fold_cm_counts
    )

    plot_confusion_matrix_panel(
        ax,
        fold_cm_counts[fold_id],
        norm_df=fold_cm_norm[fold_id],
        title=f"Fold {fold_id}",
        show_xlabel=show_xlabel,
        show_ylabel=show_ylabel,
        show_xticklabels=show_xticklabels,
        show_yticklabels=show_yticklabels,
        vmax=max_fold_value,
        show_summary=True,
    )


def panel_overall_oof_cm(
    ax,
    show_xlabel=True,
    show_ylabel=True,
    show_xticklabels=True,
    show_yticklabels=True,
):
    plot_confusion_matrix_panel(
        ax,
        oof_cm_counts,
        norm_df=oof_cm_norm,
        title="Overall OOF",
        show_xlabel=show_xlabel,
        show_ylabel=show_ylabel,
        show_xticklabels=show_xticklabels,
        show_yticklabels=show_yticklabels,
        vmax=oof_cm_counts.to_numpy().max(),
        show_summary=True,
    )


def panel_holdout_radar(ax):
    labels = list(holdout_metrics.keys())
    values = np.array([holdout_metrics[k] for k in labels], dtype=float)

    n_metrics = len(labels)
    angles = np.linspace(0, 2 * np.pi, n_metrics, endpoint=False)

    angles_closed = np.r_[angles, angles[0]]
    values_closed = np.r_[values, values[0]]

    ax.set_theta_offset(0.0)
    ax.set_theta_direction(1)

    ax.plot(
        angles_closed,
        values_closed,
        color=COLORS["blue"],
        lw=1.25,
        marker="o",
        ms=2.7,
        zorder=3,
    )

    ax.fill(
        angles_closed,
        values_closed,
        color=COLORS["blue"],
        alpha=0.11,
        zorder=2,
    )

    ax.set_xticks(angles)
    ax.set_xticklabels(labels, fontsize=6.7)

    ax.set_ylim(0.0, 1.0)
    ax.set_yticks([0.4, 0.6, 0.8, 1.0])
    ax.set_yticklabels(["0.4", "0.6", "0.8", "1.0"], fontsize=5.8)

    ax.grid(color=COLORS["grid"], lw=0.45)
    ax.spines["polar"].set_color("#AEB8C2")
    ax.spines["polar"].set_linewidth(0.62)

    ax.set_title(
        "Hold-out test metrics",
        fontsize=8.1,
        fontweight="bold",
        pad=7,
    )

    radial_offset = {
        "Accuracy": 0.145,
        "Precision": 0.105,
        "Recall": 0.125,
        "F1": 0.110,
        "ROC-AUC": 0.135,
        "PR-AUC": 0.125,
    }

    angular_shift = {
        "Accuracy": 0.000,
        "Precision": -0.030,
        "Recall": 0.030,
        "F1": 0.000,
        "ROC-AUC": -0.030,
        "PR-AUC": 0.030,
    }

    for angle, lab, val in zip(angles, labels, values):
        r_txt = val - radial_offset.get(lab, 0.11)
        r_txt = np.clip(r_txt, 0.08, 0.90)
        theta_txt = angle + angular_shift.get(lab, 0.0)

        ax.text(
            theta_txt,
            r_txt,
            f"{val:.2f}",
            ha="center",
            va="center",
            fontsize=5.8,
            color=COLORS["text"],
            zorder=6,
        )


def panel_roc(ax):
    ax.plot(
        fpr,
        tpr,
        color=COLORS["blue"],
        lw=1.55,
        label=f"ROC-AUC = {roc_auc_val:.3f}",
    )

    ax.plot(
        [0, 1],
        [0, 1],
        color=COLORS["gray"],
        lw=0.95,
        ls="--",
        label="Chance",
    )

    ax.set_title("ROC curve", fontsize=8.5, fontweight="bold", pad=3.5)
    ax.set_xlabel("False positive rate", labelpad=2.0)
    ax.set_ylabel("True positive rate", labelpad=2.0)

    ax.set_xlim(0, 1)
    ax.set_ylim(0, 1.02)

    ax.legend(
        frameon=False,
        loc="lower right",
        handlelength=2.0,
        borderaxespad=0.2,
    )

    clean_axes(ax, grid=True)


def panel_pr(ax):
    ax.plot(
        recall_arr,
        precision_arr,
        color=COLORS["teal"],
        lw=1.55,
        label=f"PR-AUC = {pr_auc_val:.3f}",
    )

    ax.axhline(
        test_prevalence,
        color=COLORS["salmon"],
        lw=0.95,
        ls="--",
        label=f"Prevalence = {test_prevalence:.2f}",
    )

    ax.set_title("Precision–recall curve", fontsize=8.5, fontweight="bold", pad=3.5)
    ax.set_xlabel("Recall", labelpad=2.0)
    ax.set_ylabel("Precision", labelpad=2.0)

    ax.set_xlim(0, 1)
    ax.set_ylim(0, 1.02)

    ax.legend(
        frameon=False,
        loc="lower left",
        handlelength=2.0,
        borderaxespad=0.2,
    )

    clean_axes(ax, grid=True)


# ------------------------------------------------------------
# 7) Save individual panels only
#    No panel labels: no (a)–(i)
#    Display each figure after saving
#    Export PNG / PDF / SVG / TIFF
#    TIFF = 900 DPI
# ------------------------------------------------------------
def save_single_panel(draw_func, filename, figsize=(3.0, 2.6), projection=None, show=True):
    if projection == "polar":
        fig_p, ax_p = plt.subplots(
            figsize=figsize,
            subplot_kw={"projection": "polar"}
        )
    else:
        fig_p, ax_p = plt.subplots(figsize=figsize)

    draw_func(ax_p)

    # PNG
    out_png = FIG4_PANEL_DIR / f"{filename}.png"
    fig_p.savefig(
        out_png,
        dpi=600,
        bbox_inches="tight",
        facecolor="white"
    )
    print("[saved panel]", out_png)

    # PDF
    out_pdf = FIG4_PANEL_DIR / f"{filename}.pdf"
    fig_p.savefig(
        out_pdf,
        format="pdf",
        bbox_inches="tight",
        facecolor="white"
    )
    print("[saved panel]", out_pdf)

    # SVG
    out_svg = FIG4_PANEL_DIR / f"{filename}.svg"
    fig_p.savefig(
        out_svg,
        format="svg",
        bbox_inches="tight",
        facecolor="white"
    )
    print("[saved panel]", out_svg)

    # TIFF, 900 DPI
    out_tiff = FIG4_PANEL_DIR / f"{filename}.tiff"

    try:
        fig_p.savefig(
            out_tiff,
            dpi=900,
            format="tiff",
            bbox_inches="tight",
            facecolor="white",
            pil_kwargs={"compression": "tiff_lzw"}
        )
    except TypeError:
        fig_p.savefig(
            out_tiff,
            dpi=900,
            format="tiff",
            bbox_inches="tight",
            facecolor="white"
        )

    print("[saved panel]", out_tiff)

    if show:
        display(fig_p)

    plt.close(fig_p)


# Fold 1–5 confusion matrices
for fold_id in range(1, 6):
    save_single_panel(
        lambda ax, fid=fold_id: panel_fold_cm(
            ax,
            fid,
            show_xlabel=True,
            show_ylabel=True,
            show_xticklabels=True,
            show_yticklabels=True,
        ),
        f"Figure4_panel_{fold_id}_fold{fold_id}_confusion_matrix_count_only_summary_title",
        figsize=(2.60, 2.42),
        show=True,
    )

# Overall OOF confusion matrix
save_single_panel(
    lambda ax: panel_overall_oof_cm(
        ax,
        show_xlabel=True,
        show_ylabel=True,
        show_xticklabels=True,
        show_yticklabels=True,
    ),
    "Figure4_panel_6_overall_oof_confusion_matrix_count_only_summary_title",
    figsize=(2.85, 2.60),
    show=True,
)

# Hold-out test metrics radar
save_single_panel(
    panel_holdout_radar,
    "Figure4_panel_7_holdout_test_metrics_radar_PR_AUC",
    figsize=(2.95, 2.95),
    projection="polar",
    show=True,
)

# ROC curve
save_single_panel(
    panel_roc,
    "Figure4_panel_8_holdout_test_roc_curve",
    figsize=(3.20, 2.55),
    show=True,
)

# Precision–recall curve
save_single_panel(
    panel_pr,
    "Figure4_panel_9_holdout_test_precision_recall_curve_PR_AUC",
    figsize=(3.20, 2.55),
    show=True,
)

print("\nFigure 4 individual panels exported and displayed.")
print("Panel dir :", FIG4_PANEL_DIR)
print("Source dir:", FIG4_SRC_DIR)


