candidate_model_names = []
for m in test_df["model_name"].astype(str).tolist():
    if m and m not in candidate_model_names:
        candidate_model_names.append(m)

print("\n[ROC candidate models]")
for m in candidate_model_names:
    print("-", m)

# =========================================================
# 3) text payload
# =========================================================
def load_payload(model_name):
    if model_name in globals() and globals()[model_name] is not None:
        obj = globals()[model_name]
        if isinstance(obj, dict):
            return obj, f"memory:{model_name}"

    file_path = os.path.join(SAVE_DIR, f"{model_name}.joblib")
    if os.path.exists(file_path):
        obj = joblib.load(file_path)
        if isinstance(obj, dict):
            return obj, f"file:{file_path}"

    return None, None

def get_test_prob_from_payload(model_name, payload):
    if not isinstance(payload, dict):
        raise ValueError(f"{model_name} payload text dict ")

    if "test_prob" not in payload or payload["test_prob"] is None:
        raise ValueError(f"{model_name} payload text test_prob text ROC ")

    test_prob = np.asarray(payload["test_prob"], dtype=float).ravel()

    if len(test_prob) != len(y_true):
        raise ValueError(f"{model_name} test_prob text prob={len(test_prob)} vs y={len(y_true)}")

    if np.isnan(test_prob).any() or np.isinf(test_prob).any():
        raise ValueError(f"{model_name} test_prob text NaN/Inf ")

    return test_prob

# =========================================================
# 4) text ROC text
# =========================================================
roc_rows = []
curves = []
skipped = []

for model_name in candidate_model_names:
    payload, payload_source = load_payload(model_name)
    if payload is None:
        skipped.append((model_name, "missing_payload"))
        continue

    try:
        test_prob = get_test_prob_from_payload(model_name, payload)
        auc = float(roc_auc_score(y_true, test_prob))
        fpr, tpr, thresholds = roc_curve(y_true, test_prob)

        curves.append({
            "model_name": model_name,
            "model_role": "primary_application_model" if model_name == PRIMARY_MODEL_NAME else "other_model",
            "auc": auc,
            "fpr": fpr,
            "tpr": tpr,
            "thresholds": thresholds,
            "payload_source": payload_source
        })

        roc_rows.append({
            "model_name": model_name,
            "model_role": "primary_application_model" if model_name == PRIMARY_MODEL_NAME else "other_model",
            "ROC-AUC_recomputed": auc,
            "payload_source": payload_source
        })

    except Exception as e:
        skipped.append((model_name, str(e)))

if len(curves) == 0:
    raise RuntimeError("text test_prob text ROC ")

roc_summary_df = pd.DataFrame(roc_rows).sort_values(
    by="ROC-AUC_recomputed", ascending=False
).reset_index(drop=True)

print("\n[ROC] Used models:")
for _, row in roc_summary_df.iterrows():
    print(f"- {row['model_name']:20s} AUC={row['ROC-AUC_recomputed']:.6f} | role={row['model_role']}")

if skipped:
    print("\n[ROC] Skipped models:")
    for model_name, reason in skipped:
        print(f"- {model_name}: {reason}")

curve_map = {item["model_name"]: item for item in curves}

if PRIMARY_MODEL_NAME not in curve_map:
    raise RuntimeError(f"text {PRIMARY_MODEL_NAME} text ROC text ")

# =========================================================
# 5) text + text
