def style_axis_journal(ax, grid=False):
    """
    Multi-panel compatible style:
    - remove top/right spines
    - keep left/bottom axes
    - no background grid
    """
    ax.spines["top"].set_visible(False)
    ax.spines["right"].set_visible(False)

    ax.spines["left"].set_linewidth(0.65)
    ax.spines["bottom"].set_linewidth(0.65)
    ax.spines["left"].set_color(AXIS_COLOR)
    ax.spines["bottom"].set_color(AXIS_COLOR)

    ax.tick_params(
        axis="both",
        colors=AXIS_COLOR,
        labelcolor=AXIS_COLOR,
        width=0.55,
        length=2.4,
        pad=2.0,
    )

    ax.grid(False)
    ax.set_axisbelow(True)


def soften_legend(leg):
    """
    Remove heavy legend frame for journal-style panels.
    """
    if leg is not None:
        leg.set_frame_on(False)
        for txt in leg.get_texts():
            txt.set_fontsize(6.0)


def smooth_series(y, window=5):
    y = np.asarray(y, dtype=float)

    if window <= 1 or len(y) < window:
        return y.copy()

    pad = window // 2
    y_pad = np.pad(y, (pad, pad), mode="edge")
    kernel = np.ones(window) / window

    return np.convolve(y_pad, kernel, mode="valid")


def subsample_runs(all_scores, all_classes, max_runs=8, seed=42):
    n_runs = len(all_scores)

    if n_runs <= max_runs:
        return all_scores, all_classes

    rng_local = np.random.default_rng(seed)
    idx = np.sort(rng_local.choice(np.arange(n_runs), size=max_runs, replace=False))

    return [all_scores[i] for i in idx], [all_classes[i] for i in idx]


def make_pr_curve_sorted(y, scores):
    precision, recall, _ = precision_recall_curve(y, scores)

    recall = recall[::-1]
    precision = precision[::-1]

    recall_u, idx = np.unique(recall, return_index=True)
    precision_u = precision[idx]

    if recall_u[0] > 0:
        recall_u = np.insert(recall_u, 0, 0.0)
        precision_u = np.insert(precision_u, 0, precision_u[0])

    if recall_u[-1] < 1:
        recall_u = np.append(recall_u, 1.0)
        precision_u = np.append(precision_u, precision_u[-1])

    return recall_u, precision_u


def enrichment_curve(y, scores, max_percent=20.0, step=0.5):
    y = np.asarray(y).astype(int)
    scores = np.asarray(scores, dtype=float)

    order = np.argsort(-scores)
    y_sorted = y[order]

    n_local = len(y_sorted)
    n_pos = np.sum(y_sorted)

    if n_pos == 0:
        raise ValueError("text text enrichment ")

    percents = np.arange(step, max_percent + 1e-12, step)
    ef_vals = []

    for p in percents:
        frac = p / 100.0
        top_k = max(1, int(np.ceil(n_local * frac)))
        hits_top = np.sum(y_sorted[:top_k])
        expected_hits = n_pos * frac
        ef = hits_top / expected_hits if expected_hits > 0 else np.nan
        ef_vals.append(ef)

    return percents, np.asarray(ef_vals, dtype=float)


# ------------------------------
# Panel 1. Test score separation
# ------------------------------
def draw_score_distribution(ax, y_true, test_prob):
    """
    Figure 3-compatible score distribution panel.
    """
    y_true = np.asarray(y_true).astype(int).ravel()
    test_prob = np.asarray(test_prob, dtype=float).ravel()

    neg_scores = test_prob[y_true == 0]
    pos_scores = test_prob[y_true == 1]

    if HAS_SEABORN:
        sns.kdeplot(
            x=neg_scores,
            fill=True,
            alpha=0.34,
            linewidth=1.05,
            color=LOW_COLOR,
            label="Non-high",
            ax=ax,
        )

        sns.kdeplot(
            x=pos_scores,
            fill=True,
            alpha=0.32,
            linewidth=1.05,
            color=HIGH_COLOR,
            label="High-delivery",
            ax=ax,
        )
    else:
        ax.hist(
            neg_scores,
            bins=20,
            density=True,
            alpha=0.34,
            color=LOW_COLOR,
            label="Non-high",
        )

        ax.hist(
            pos_scores,
            bins=20,
            density=True,
            alpha=0.32,
            color=HIGH_COLOR,
            label="High-delivery",
        )

    ax.set_title("Test score separation", fontsize=7.8, fontweight="bold", pad=2.5)
    ax.set_xlabel("Predicted score", fontsize=7.2, labelpad=1.8)
    ax.set_ylabel("Density", fontsize=7.2, labelpad=1.8)

    style_axis_journal(ax, grid=False)

    ax.tick_params(axis="both", labelsize=6.6, width=0.55, length=2.4, pad=2.0)

    leg = ax.legend(
        loc="upper right",
        frameon=False,
        fontsize=5.8,
        handlelength=1.0,
        handletextpad=0.30,
        borderaxespad=0.15,
        labelspacing=0.15,
    )
    soften_legend(leg)


# ------------------------------
# Panel 2. ROC
# ------------------------------
def draw_roc_panel(ax, all_scores, all_classes):
    mean_fpr = np.linspace(0, 1, 500)
    tprs, aucs = [], []

    bg_scores, bg_classes = subsample_runs(
        all_scores,
        all_classes,
        MAX_BG_RUNS,
        RANDOM_STATE_PLOT,
    )

    for scores, classes in zip(bg_scores, bg_classes):
        fpr, tpr, _ = roc_curve(classes, scores)
        ax.plot(fpr, tpr, lw=0.55, alpha=0.13, color=BG_COLOR)

    for scores, classes in zip(all_scores, all_classes):
        fpr, tpr, _ = roc_curve(classes, scores)
        roc_auc = auc(fpr, tpr)

        interp_tpr = np.interp(mean_fpr, fpr, tpr)
        interp_tpr[0] = 0.0
        interp_tpr[-1] = 1.0

        tprs.append(interp_tpr)
        aucs.append(roc_auc)

    mean_tpr = np.mean(tprs, axis=0)
    std_tpr = np.std(tprs, axis=0)

    mean_auc = float(np.mean(aucs))
    std_auc = float(np.std(aucs))

    lower = np.maximum(mean_tpr - std_tpr, 0)
    upper = np.minimum(mean_tpr + std_tpr, 1)

    ax.fill_between(
        mean_fpr,
        lower,
        upper,
        color=BAND_COLOR,
        alpha=0.13,
        label="±1 SD",
    )

    ax.plot(
        mean_fpr,
        mean_tpr,
        lw=1.55,
        color=MAIN_BLUE,
        label=f"AUC-ROC = {mean_auc:.3f} ± {std_auc:.3f}",
    )

    ax.plot(
        [0, 1],
        [0, 1],
        "--",
        lw=0.95,
        color=CHANCE_COLOR,
        label="Chance",
    )

    # text text text
    ax.set_xlim(-0.005, 1.005)
    ax.set_ylim(-0.015, 1.035)

    # text 0–1
    ax.set_xticks(np.linspace(0, 1, 6))
    ax.set_yticks(np.linspace(0, 1, 6))

    ax.set_xlabel("False positive rate", labelpad=2.0)
    ax.set_ylabel("True positive rate", labelpad=2.0)
    ax.set_title("ROC curve", pad=3)

    style_axis_journal(ax, grid=False)

    leg = ax.legend(
        loc="lower right",
        frameon=False,
        handlelength=1.8,
        borderaxespad=0.25,
    )
    soften_legend(leg)


# ------------------------------
# Panel 3. PR
# ------------------------------
def draw_pr_panel(ax, all_scores, all_classes):
    mean_recall = np.linspace(0, 1, 500)
    interp_precisions, aucs = [], []

    positive_rate = float(np.mean(np.concatenate(all_classes)))

    bg_scores, bg_classes = subsample_runs(
        all_scores,
        all_classes,
        MAX_BG_RUNS,
        RANDOM_STATE_PLOT,
    )

    for scores, classes in zip(bg_scores, bg_classes):
        recall_u, precision_u = make_pr_curve_sorted(classes, scores)
        ax.plot(recall_u, precision_u, lw=0.55, alpha=0.13, color=BG_COLOR)

    for scores, classes in zip(all_scores, all_classes):
        recall_u, precision_u = make_pr_curve_sorted(classes, scores)
        pr_auc = auc(recall_u, precision_u)

        interp_precision = np.interp(mean_recall, recall_u, precision_u)

        interp_precisions.append(interp_precision)
        aucs.append(pr_auc)

    mean_precision = np.mean(interp_precisions, axis=0)
    std_precision = np.std(interp_precisions, axis=0)

    mean_auc = float(np.mean(aucs))
    std_auc = float(np.std(aucs))

    lower = np.maximum(mean_precision - std_precision, 0)
    upper = np.minimum(mean_precision + std_precision, 1)

    ax.fill_between(
        mean_recall,
        lower,
        upper,
        color=BAND_COLOR,
        alpha=0.13,
        label="±1 SD",
    )

    ax.plot(
        mean_recall,
        mean_precision,
        lw=1.55,
        color=MAIN_BLUE,
        label=f"PR-AUC = {mean_auc:.3f} ± {std_auc:.3f}",
    )

    ax.axhline(
        y=positive_rate,
        linestyle="--",
        lw=0.95,
        color=CHANCE_COLOR,
        label=f"Prevalence = {positive_rate:.3f}",
    )

    # text text text precision=1.0 text
    ax.set_xlim(-0.005, 1.005)
    ax.set_ylim(-0.015, 1.035)

    # text 0–1
    ax.set_xticks(np.linspace(0, 1, 6))
    ax.set_yticks(np.linspace(0, 1, 6))

    ax.set_xlabel("Recall", labelpad=2.0)
    ax.set_ylabel("Precision", labelpad=2.0)
    ax.set_title("Precision–recall curve", pad=3)

    style_axis_journal(ax, grid=False)

    leg = ax.legend(
        loc="lower left",
        frameon=False,
        handlelength=1.8,
        borderaxespad=0.25,
    )
    soften_legend(leg)


# ------------------------------
# Panel 4. Enrichment
# ------------------------------
def draw_enrichment_panel(ax, all_scores, all_classes):
    all_ef = []
    percent_grid = None

    bg_scores, bg_classes = subsample_runs(
        all_scores,
        all_classes,
        MAX_BG_RUNS,
        RANDOM_STATE_PLOT,
    )

    for scores, classes in zip(bg_scores, bg_classes):
        percents, ef_vals = enrichment_curve(
            classes,
            scores,
            MAX_ENRICH_PERCENT,
            ENRICH_STEP,
        )
        ef_vals_show = smooth_series(ef_vals, window=ENRICH_SMOOTH_WINDOW)
        ax.plot(percents, ef_vals_show, lw=0.55, alpha=0.14, color=BG_COLOR)

    for scores, classes in zip(all_scores, all_classes):
        percents, ef_vals = enrichment_curve(
            classes,
            scores,
            MAX_ENRICH_PERCENT,
            ENRICH_STEP,
        )
        ef_vals_show = smooth_series(ef_vals, window=ENRICH_SMOOTH_WINDOW)

        if percent_grid is None:
            percent_grid = percents

        all_ef.append(ef_vals_show)

    mean_ef = np.mean(all_ef, axis=0)
    std_ef = np.std(all_ef, axis=0)

    lower = np.maximum(mean_ef - std_ef, 0)
    upper = mean_ef + std_ef

    ax.fill_between(
        percent_grid,
        lower,
        upper,
        color=BAND_COLOR,
        alpha=0.13,
    )

    ax.plot(
        percent_grid,
        mean_ef,
        lw=1.55,
        color=MAIN_BLUE,
        label="Mean enrichment",
    )

    ax.set_xlim(0, MAX_ENRICH_PERCENT)

    y_top = np.nanpercentile(np.concatenate(all_ef), 98)
    ax.set_ylim(0, max(5.0, min(y_top * 1.10, 10.0)))

    ax.set_xlabel("Top-ranked percentage (%)", labelpad=2.0)
    ax.set_ylabel("Enrichment factor", labelpad=2.0)
    # ax.set_title("Enrichment plot", pad=3)

    style_axis_journal(ax, grid=False)

    leg = ax.legend(
        loc="upper right",
        frameon=False,
        handlelength=1.8,
        borderaxespad=0.25,
    )
    soften_legend(leg)


