def export_single_panel(draw_func, filename, figsize=(3.15, 2.45), show=True):
    fig, ax = plt.subplots(figsize=figsize)

    draw_func(ax)

    fig.subplots_adjust(
        left=0.17,
        right=0.97,
        bottom=0.17,
        top=0.88,
    )

    for ext in ["png", "pdf", "svg"]:
        out_path = os.path.join(PANEL_DIR, f"{filename}.{ext}")
        fig.savefig(out_path, facecolor="white")
        print("[saved panel]", out_path)

    if show:
        plt.show()

    plt.close(fig)


