# ------------------------------
# text
# ------------------------------
def style_axis_journal(ax):
    ax.spines["top"].set_visible(True)
    ax.spines["right"].set_visible(True)
    ax.spines["left"].set_linewidth(0.85)
    ax.spines["bottom"].set_linewidth(0.85)
    ax.grid(False)
    ax.set_axisbelow(True)

def add_panel_label_outside(fig, ax, label, dx=0.055, dy=0.012):
    """
    text figure text text
    dx: text
    dy: text
    """
    bbox = ax.get_position()
    x = bbox.x0 - dx
    y = bbox.y1 + dy
    fig.text(
        x, y, label,
        ha="left",
        va="top",
        fontsize=11.5,
        fontweight="bold"
    )

def soften_legend(leg):
    if leg is not None:
        leg.get_frame().set_alpha(0.95)
        leg.get_frame().set_edgecolor("0.8")
        leg.get_frame().set_linewidth(0.75)

def smooth_series(y, window=5):
    y = np.asarray(y, dtype=float)
    if window <= 1 or len(y) < window:
        return y.copy()
    pad = window // 2
    y_pad = np.pad(y, (pad, pad), mode="edge")
    kernel = np.ones(window) / window
    return np.convolve(y_pad, kernel, mode="valid")

def subsample_runs(all_scores, all_classes, max_runs=8, seed=42):
    n_runs = len(all_scores)
    if n_runs <= max_runs:
        return all_scores, all_classes
    rng_local = np.random.default_rng(seed)
    idx = np.sort(rng_local.choice(np.arange(n_runs), size=max_runs, replace=False))
    return [all_scores[i] for i in idx], [all_classes[i] for i in idx]

def make_pr_curve_sorted(y, scores):
    precision, recall, _ = precision_recall_curve(y, scores)

    recall = recall[::-1]
    precision = precision[::-1]

    recall_u, idx = np.unique(recall, return_index=True)
    precision_u = precision[idx]

    if recall_u[0] > 0:
        recall_u = np.insert(recall_u, 0, 0.0)
        precision_u = np.insert(precision_u, 0, precision_u[0])
    if recall_u[-1] < 1:
        recall_u = np.append(recall_u, 1.0)
        precision_u = np.append(precision_u, precision_u[-1])

    return recall_u, precision_u

def enrichment_curve(y, scores, max_percent=20.0, step=0.5):
    y = np.asarray(y).astype(int)
    scores = np.asarray(scores, dtype=float)

    order = np.argsort(-scores)
    y_sorted = y[order]

    n_local = len(y_sorted)
    n_pos = np.sum(y_sorted)
    if n_pos == 0:
        raise ValueError("text text enrichment ")

    percents = np.arange(step, max_percent + 1e-12, step)
    ef_vals = []

    for p in percents:
        frac = p / 100.0
        top_k = max(1, int(np.ceil(n_local * frac)))
        hits_top = np.sum(y_sorted[:top_k])
        expected_hits = n_pos * frac
        ef = hits_top / expected_hits if expected_hits > 0 else np.nan
        ef_vals.append(ef)

    return percents, np.asarray(ef_vals, dtype=float)

# ------------------------------
# (A) Predicted score distribution
# ------------------------------
def draw_score_distribution(ax, y_true, test_prob):
    y_true = np.asarray(y_true).astype(int).ravel()
    test_prob = np.asarray(test_prob, dtype=float).ravel()

    neg_scores = test_prob[y_true == 0]
    pos_scores = test_prob[y_true == 1]

    if HAS_SEABORN:
        sns.kdeplot(
            x=neg_scores,
            fill=True,
            alpha=0.62,
            linewidth=1.4,
            color=LOW_COLOR,
            label="Low-delivery",
            ax=ax
        )
        sns.kdeplot(
            x=pos_scores,
            fill=True,
            alpha=0.55,
            linewidth=1.4,
            color=HIGH_COLOR,
            label="High-delivery",
            ax=ax
        )
    else:
        ax.hist(neg_scores, bins=20, density=True, alpha=0.55, color=LOW_COLOR, label="Low-delivery")
        ax.hist(pos_scores, bins=20, density=True, alpha=0.50, color=HIGH_COLOR, label="High-delivery")

    ax.set_title("Predicted score distribution", pad=2)
    ax.set_xlabel("Predicted score")
    ax.set_ylabel("Density")
    style_axis_journal(ax)

    leg = ax.legend(loc="upper right", frameon=True)
    soften_legend(leg)

# ------------------------------
# (B) ROC
# ------------------------------
def draw_roc_panel(ax, all_scores, all_classes):
    mean_fpr = np.linspace(0, 1, 500)
    tprs, aucs = [], []

    bg_scores, bg_classes = subsample_runs(all_scores, all_classes, MAX_BG_RUNS, RANDOM_STATE_PLOT)

    for scores, classes in zip(bg_scores, bg_classes):
        fpr, tpr, _ = roc_curve(classes, scores)
        ax.plot(fpr, tpr, lw=0.8, alpha=0.12, color=BG_COLOR)

    for scores, classes in zip(all_scores, all_classes):
        fpr, tpr, _ = roc_curve(classes, scores)
        roc_auc = auc(fpr, tpr)

        interp_tpr = np.interp(mean_fpr, fpr, tpr)
        interp_tpr[0] = 0.0
        interp_tpr[-1] = 1.0
        tprs.append(interp_tpr)
        aucs.append(roc_auc)

    mean_tpr = np.mean(tprs, axis=0)
    std_tpr = np.std(tprs, axis=0)
    mean_auc = float(np.mean(aucs))
    std_auc = float(np.std(aucs))

    lower = np.maximum(mean_tpr - std_tpr, 0)
    upper = np.minimum(mean_tpr + std_tpr, 1)

    ax.fill_between(mean_fpr, lower, upper, color=BAND_COLOR, alpha=0.12, label="±1 SD")
    ax.plot(mean_fpr, mean_tpr, lw=2.0, color=MAIN_BLUE, label=f"AUC-ROC = {mean_auc:.3f} ± {std_auc:.3f}")
    ax.plot([0, 1], [0, 1], "--", lw=1.4, color=CHANCE_COLOR, label="Chance")

    ax.set_xlim(0, 1)
    ax.set_ylim(0, 1)
    ax.set_xlabel("False Positive Rate")
    ax.set_ylabel("True Positive Rate")
    ax.set_title("ROC curve", pad=2)
    style_axis_journal(ax)

    leg = ax.legend(loc="lower right", frameon=True)
    soften_legend(leg)

# ------------------------------
# (C) PR
# ------------------------------
def draw_pr_panel(ax, all_scores, all_classes):
    mean_recall = np.linspace(0, 1, 500)
    interp_precisions, aucs = [], []

    positive_rate = float(np.mean(np.concatenate(all_classes)))

    bg_scores, bg_classes = subsample_runs(all_scores, all_classes, MAX_BG_RUNS, RANDOM_STATE_PLOT)

    for scores, classes in zip(bg_scores, bg_classes):
        recall_u, precision_u = make_pr_curve_sorted(classes, scores)
        ax.plot(recall_u, precision_u, lw=0.8, alpha=0.12, color=BG_COLOR)

    for scores, classes in zip(all_scores, all_classes):
        recall_u, precision_u = make_pr_curve_sorted(classes, scores)
        pr_auc = auc(recall_u, precision_u)

        interp_precision = np.interp(mean_recall, recall_u, precision_u)
        interp_precisions.append(interp_precision)
        aucs.append(pr_auc)

    mean_precision = np.mean(interp_precisions, axis=0)
    std_precision = np.std(interp_precisions, axis=0)
    mean_auc = float(np.mean(aucs))
    std_auc = float(np.std(aucs))

    lower = np.maximum(mean_precision - std_precision, 0)
    upper = np.minimum(mean_precision + std_precision, 1)

    ax.fill_between(mean_recall, lower, upper, color=BAND_COLOR, alpha=0.12, label="±1 SD")
    ax.plot(mean_recall, mean_precision, lw=2.0, color=MAIN_BLUE, label=f"AUC-PRC = {mean_auc:.3f} ± {std_auc:.3f}")
    ax.axhline(y=positive_rate, linestyle="--", lw=1.4, color=CHANCE_COLOR, label=f"Prevalence = {positive_rate:.3f}")

    ax.set_xlim(0, 1)
    ax.set_ylim(0, 1)
    ax.set_xlabel("Recall")
    ax.set_ylabel("Precision")
    ax.set_title("PR curve", pad=2)
    style_axis_journal(ax)

    leg = ax.legend(loc="lower left", frameon=True)
    soften_legend(leg)

# ------------------------------
# (D) Enrichment
# ------------------------------
def draw_enrichment_panel(ax, all_scores, all_classes):
    all_ef = []
    percent_grid = None

    bg_scores, bg_classes = subsample_runs(all_scores, all_classes, MAX_BG_RUNS, RANDOM_STATE_PLOT)

    for scores, classes in zip(bg_scores, bg_classes):
        percents, ef_vals = enrichment_curve(classes, scores, MAX_ENRICH_PERCENT, ENRICH_STEP)
        ef_vals_show = smooth_series(ef_vals, window=ENRICH_SMOOTH_WINDOW)
        ax.plot(percents, ef_vals_show, lw=0.8, alpha=0.16, color=BG_COLOR)

    for scores, classes in zip(all_scores, all_classes):
        percents, ef_vals = enrichment_curve(classes, scores, MAX_ENRICH_PERCENT, ENRICH_STEP)
        ef_vals_show = smooth_series(ef_vals, window=ENRICH_SMOOTH_WINDOW)
        if percent_grid is None:
            percent_grid = percents
        all_ef.append(ef_vals_show)

    mean_ef = np.mean(all_ef, axis=0)
    std_ef = np.std(all_ef, axis=0)

    lower = np.maximum(mean_ef - std_ef, 0)
    upper = mean_ef + std_ef

    ax.fill_between(percent_grid, lower, upper, color=BAND_COLOR, alpha=0.12)
    ax.plot(percent_grid, mean_ef, lw=2.0, color=MAIN_BLUE, label="Mean enrichment")

    ax.set_xlim(0, MAX_ENRICH_PERCENT)

    y_top = np.nanpercentile(np.concatenate(all_ef), 98)
    ax.set_ylim(0, max(5.0, min(y_top * 1.10, 10.0)))

    ax.set_xlabel("Top-ranked percentage (%)")
    ax.set_ylabel("Enrichment factor")
    ax.set_title("Enrichment plot", pad=2)
    style_axis_journal(ax)

    leg = ax.legend(loc="upper right", frameon=True)
    soften_legend(leg)

# ------------------------------
# text
# ------------------------------
def plot_compact_screening_figure_v10(
    y_true,
    test_prob,
    all_scores,
    all_classes,
    out_png,
    out_pdf,
    out_svg
):
    fig, axes = plt.subplots(2, 2, figsize=(8.45, 6.45))

    draw_score_distribution(axes[0, 0], y_true, test_prob)
    draw_roc_panel(axes[0, 1], all_scores, all_classes)
    draw_pr_panel(axes[1, 0], all_scores, all_classes)
    draw_enrichment_panel(axes[1, 1], all_scores, all_classes)

    fig.subplots_adjust(
        left=0.09, right=0.985, top=0.96, bottom=0.08,
        wspace=0.22, hspace=0.33
    )

    # text text layout text
    fig.canvas.draw()

    panel_tags = ["A", "B", "C", "D"]
    for tag, ax in zip(panel_tags, axes.ravel()):
        add_panel_label_outside(fig, ax, tag, dx=0.05, dy=0.012)

    plt.savefig(out_png, bbox_inches="tight", facecolor="white")
    plt.savefig(out_pdf, bbox_inches="tight", facecolor="white")
    plt.savefig(out_svg, bbox_inches="tight", facecolor="white")
    plt.show()
    plt.close(fig)

