def precision_at_k(y_sorted, k):
    k = min(int(k), len(y_sorted))
    k = max(k, 1)
    return np.sum(y_sorted[:k] == 1) / k

def recall_at_k(y_sorted, k):
    k = min(int(k), len(y_sorted))
    k = max(k, 1)
    return np.sum(y_sorted[:k] == 1) / np.sum(y_sorted == 1)

