def export_current_figure(fig, out_base):
    """
    text png / svg / tiff
    PNG text TIFF text 900 DPI
    SVG text text DPI
    """
    fig.savefig(
        out_base.with_suffix(".png"),
        dpi=EXPORT_DPI,
        bbox_inches="tight",
        facecolor="white"
    )

    fig.savefig(
        out_base.with_suffix(".svg"),
        bbox_inches="tight",
        facecolor="white"
    )

    fig.savefig(
        out_base.with_suffix(".tiff"),
        dpi=EXPORT_DPI,
        bbox_inches="tight",
        facecolor="white"
    )

    print("Exported:")
    print(out_base.with_suffix(".png"))
    print(out_base.with_suffix(".svg"))
    print(out_base.with_suffix(".tiff"))

def annotate_points_jcr(ax, xs, ys, labels, ylim, mode="default"):
    """
    JCR text
    - Precision@k text k=5 / k=10 / k=20 text
    - text
    - text text
    - text
    """
    y_span = ylim[1] - ylim[0]

    for x, y, label in zip(xs, ys, labels):
        x_text = x
        y_text = y + 0.045 * y_span
        va = "bottom"

        # text text text
        if y > ylim[0] + 0.88 * y_span:
            y_text = y - 0.065 * y_span
            va = "top"

        # Precision@k text k=5 / k=10 / k=20 text
        if mode == "precision":
            if "k=5" in label:
                x_text = x - 0.55
                y_text = y + 0.055 * y_span
                va = "bottom"
            elif "k=10" in label:
                x_text = x + 0.55
                y_text = y + 0.055 * y_span
                va = "bottom"
            elif "k=20" in label:
                x_text = x + 0.25
                y_text = y + 0.055 * y_span
                va = "bottom"

        # EF@k supplement
        if mode == "ef":
            if "k=5" in label:
                x_text = x - 0.25
            elif "k=10" in label:
                x_text = x + 0.25

            y_text = y - 0.080 * y_span
            va = "top"

            if "k=20" in label:
                y_text = y + 0.050 * y_span
                va = "bottom"

        # Fractional enrichment supplement
        if mode == "fraction":
            y_text = y + 0.050 * y_span
            va = "bottom"

            if y > ylim[0] + 0.86 * y_span:
                y_text = y - 0.080 * y_span
                va = "top"

        ax.text(
            x_text,
            y_text,
            label,
            ha="center",
            va=va,
            fontsize=4.8,
            color=text_color,
            linespacing=0.84,
            zorder=5,
            bbox=dict(
                facecolor="white",
                edgecolor="none",
                alpha=0.72,
                pad=0.22
            ),
            clip_on=False
        )

def add_baseline_label(ax, x_pos, y_pos, label, ylim):
    """
    baseline text
    - test prevalence text
    - text
    - text
    """
    y_span = ylim[1] - ylim[0]

    ax.text(
        x_pos - 0.45,
        y_pos + y_span * 0.030,
        label,
        ha="right",
        va="bottom",
        fontsize=5.0,
        color=baseline_text_color,
        alpha=1.00,
        zorder=4
    )

def plot_single_curve_panel_jcr(
    x,
    y,
    title,
    xlabel,
    ylabel,
    ylim,
    out_name,
    baseline=None,
    baseline_label=None,
    highlight_x=None,
    highlight_y=None,
    highlight_labels=None,
    xlim=None,
    xticks=None,
    yticks=None,
    annotation_mode="default",
    panel_label=None,
    show_title=True,
):
    fig, ax = plt.subplots(figsize=SINGLE_FIGSIZE, dpi=DISPLAY_DPI)

    # text text Figure 3(f) Enrichment plot text
    ax.plot(
        x,
        y,
        color=main_color,
        linewidth=1.08,
        solid_capstyle="round",
        solid_joinstyle="round",
        zorder=3
    )

    # baseline
    if baseline is not None:
        ax.axhline(
            baseline,
            color=baseline_color,
            linestyle=(0, (3, 2)),
            linewidth=0.70,
            alpha=0.65,
            zorder=1
        )

        if baseline_label is not None:
            x_for_label = xlim[1] if xlim is not None else x[-1]
            add_baseline_label(ax, x_for_label, baseline, baseline_label, ylim)

    # highlight points
    if highlight_x is not None and highlight_y is not None:
        ax.scatter(
            highlight_x,
            highlight_y,
            s=12,
            color=main_color_dark,
            edgecolor="white",
            linewidth=0.35,
            zorder=4
        )

        if highlight_labels is not None:
            annotate_points_jcr(
                ax=ax,
                xs=highlight_x,
                ys=highlight_y,
                labels=highlight_labels,
                ylim=ylim,
                mode=annotation_mode
            )

    # text Figure 3 text Precision@k / Recall@k text
    if show_title and title:
        ax.set_title(
            title,
            loc="left",
            pad=2.2,
            fontweight="semibold"
        )

    ax.set_xlabel(xlabel, labelpad=1.8)
    ax.set_ylabel(ylabel, labelpad=1.8)
    ax.set_ylim(*ylim)

    if xlim is not None:
        ax.set_xlim(*xlim)

    if xticks is not None:
        ax.set_xticks(xticks)

    if yticks is not None:
        ax.set_yticks(yticks)

    style_axis_jcr_compact(ax)

    # text panel label text
    if panel_label is not None:
        ax.text(
            -0.18,
            1.08,
            panel_label,
            transform=ax.transAxes,
            ha="left",
            va="bottom",
            fontsize=6.8,
            fontweight="bold",
            color=text_color
        )

    fig.tight_layout(pad=0.22)

    out_base = OUT_DIR / out_name
    export_current_figure(fig, out_base)

    plt.show()
    plt.close(fig)

