# =========================================================
def load_payload(model_name):
    if model_name in globals() and globals()[model_name] is not None:
        obj = globals()[model_name]
        if isinstance(obj, dict):
            return obj, f"memory:{model_name}"

    file_path = os.path.join(SAVE_DIR, f"{model_name}.joblib")
    if os.path.exists(file_path):
        obj = joblib.load(file_path)
        if isinstance(obj, dict):
            return obj, f"file:{file_path}"

    if "loaded_model_payloads" in globals():
        lmp = globals()["loaded_model_payloads"]
        if isinstance(lmp, dict) and model_name in lmp:
            item = lmp[model_name]
            if isinstance(item, dict) and "payload" in item and isinstance(item["payload"], dict):
                return item["payload"], f"loaded_model_payloads:{model_name}"

    return None, None

def get_test_prob_from_payload(model_name, payload, y_true):
    if not isinstance(payload, dict):
        raise ValueError(f"{model_name} payload text dict ")

    if "test_prob" not in payload or payload["test_prob"] is None:
        raise ValueError(f"{model_name} payload text test_prob ")

    test_prob = np.asarray(payload["test_prob"], dtype=float).ravel()

    if len(test_prob) != len(y_true):
        raise ValueError(
            f"{model_name} test_prob text prob={len(test_prob)} vs y={len(y_true)}"
        )

    if np.isnan(test_prob).any() or np.isinf(test_prob).any():
        raise ValueError(f"{model_name} test_prob text NaN/Inf ")

    return test_prob

# =========================================================
# 9) Precision@K text Wilson text
# =========================================================
def top_k_hits_and_precision(y_true, scores, k):
    y_true = np.asarray(y_true).astype(int).ravel()
    scores = np.asarray(scores, dtype=float).ravel()

    k = min(int(k), len(y_true))
    order = np.argsort(-scores)
    top_idx = order[:k]
    hits = int(np.sum(y_true[top_idx]))
    precision = hits / k
    return hits, precision

def wilson_interval(hits, n, z=1.96):
    if n <= 0:
        return np.nan, np.nan

    p = hits / n
    denom = 1.0 + z**2 / n
    center = (p + z**2 / (2 * n)) / denom
    half = (z / denom) * math.sqrt((p * (1 - p) / n) + (z**2 / (4 * n**2)))

    lower = max(0.0, center - half)
    upper = min(1.0, center + half)
    return lower, upper

# =========================================================
# 10) text
# =========================================================
plot_records = []
used_models = []
skipped_models = []

for model_name in FOCUS_MODELS:
    payload, payload_source = load_payload(model_name)
    if payload is None:
        skipped_models.append((model_name, "payload text"))
        continue

    try:
        test_prob = get_test_prob_from_payload(model_name, payload, y_true)
    except Exception as e:
        skipped_models.append((model_name, str(e)))
        continue

    used_models.append(model_name)

    for k in K_LIST:
        hits, precision = top_k_hits_and_precision(y_true, test_prob, k)
        lower, upper = wilson_interval(hits, k, z=WILSON_Z)

        plot_records.append({
            "model_name": model_name,
            "display_name": DISPLAY_NAME_MAP.get(model_name, model_name),
            "model_role": "primary_model" if model_name == PRIMARY_MODEL_NAME else "other_model",
            "K": int(k),
            "hits": int(hits),
            "precision": float(precision),
            "lower": float(lower),
            "upper": float(upper),
            "payload_source": payload_source,
        })

plot_df = pd.DataFrame(plot_records)

