def apply_pub_style(ax, grid_axis="both", add_zero_hline=False, add_zero_vline=False):
    ax.spines["top"].set_visible(False)
    ax.spines["right"].set_visible(False)
    ax.spines["left"].set_linewidth(STYLE_CFG["spine_lw"])
    ax.spines["bottom"].set_linewidth(STYLE_CFG["spine_lw"])
    ax.tick_params(axis="both", which="major", length=4, width=0.8)

    if grid_axis is not None:
        ax.grid(
            axis=grid_axis,
            linestyle="--",
            linewidth=STYLE_CFG["grid_lw"],
            alpha=STYLE_CFG["grid_alpha"]
        )

    if add_zero_hline:
        ax.axhline(
            0,
            color=STYLE_CFG["zero_line_color"],
            lw=0.9,
            alpha=0.85,
            zorder=0
        )

    if add_zero_vline:
        ax.axvline(
            0,
            color=STYLE_CFG["zero_line_color"],
            lw=0.9,
            alpha=0.85,
            zorder=0
        )

def save_current_figure(out_base):
    """
    text
    - PNG: 900 dpi
    - SVG: text
    - TIFF: 900 dpi
    text PDF
    """
    png_path = out_base + ".png"
    svg_path = out_base + ".svg"
    tiff_path = out_base + ".tiff"

    plt.savefig(png_path, dpi=EXPORT_DPI, bbox_inches="tight", facecolor="white")
    plt.savefig(svg_path, bbox_inches="tight", facecolor="white")
    plt.savefig(tiff_path, dpi=EXPORT_DPI, bbox_inches="tight", facecolor="white")

    print(f"[Saved] {png_path}")
    print(f"[Saved] {svg_path}")
    print(f"[Saved] {tiff_path}")

    return {
        "png": png_path,
        "svg": svg_path,
        "tiff": tiff_path
    }


