def find_group_feature(target_name, names_group):
    if target_name in names_group:
        return target_name

    lower_map = {str(n).lower(): n for n in names_group}
    if str(target_name).lower() in lower_map:
        return lower_map[str(target_name).lower()]

    raise ValueError(
        f"text {target_name} text names_group text \n"
        f"text {names_group}"
    )

def get_dependence_x(feature_name, group_index):
    """
    text
    text text X_group
    """
    if (
        DEPENDENCE_USE_RAW_X
        and raw_df_explain is not None
        and feature_name in raw_df_explain.columns
    ):
        return raw_df_explain[feature_name].reset_index(drop=True), "raw"

    return pd.Series(X_group[:, group_index], name=feature_name), "processed"

def sanitize_feature_name(name):
    return str(name).replace("/", "_").replace(" ", "_")

def plot_size_dependence(feature_name="Size"):
    real_feature = find_group_feature(feature_name, names_group)
    i_feat = names_group.index(real_feature)

    x_series, x_source = get_dependence_x(real_feature, i_feat)
    y_dep = sv_group[:, i_feat].copy()

    x_dep = pd.to_numeric(pd.Series(x_series), errors="coerce").to_numpy()

    q_low, q_high = DEPENDENCE_CLIP_Q
    x_q1, x_q99 = np.nanpercentile(x_dep, [q_low, q_high])

    mask = np.isfinite(x_dep) & np.isfinite(y_dep)
    mask = mask & (x_dep >= x_q1) & (x_dep <= x_q99)

    x_plot = x_dep[mask].copy()
    y_plot = y_dep[mask].copy()

    x_label = real_feature

    if DEPENDENCE_LOG1P and np.nanmin(x_plot) >= 0:
        x_plot = np.log1p(x_plot)
        x_label = f"log1p({real_feature})"

    fig, ax = plt.subplots(figsize=(5.8, 4.9))

    ax.scatter(
        x_plot,
        y_plot,
        s=22,
        alpha=STYLE_CFG["point_alpha"],
        edgecolors="none",
        color=STYLE_CFG["scatter_color"]
    )

    ax.axhline(
        0,
        color=STYLE_CFG["zero_line_color"],
        lw=0.9,
        alpha=0.85,
        zorder=0
    )

    ax.set_xlabel("Size")
    ax.set_ylabel("SHAP value for Size")

    # text
    # ax.set_title("CatBoost dependence plot for Size")

    ax.spines["top"].set_visible(False)
    ax.spines["right"].set_visible(False)
    ax.spines["left"].set_linewidth(STYLE_CFG["spine_lw"])
    ax.spines["bottom"].set_linewidth(STYLE_CFG["spine_lw"])
    ax.tick_params(axis="both", which="major", length=4, width=0.8)

    ax.grid(
        axis="both",
        linestyle="--",
        linewidth=STYLE_CFG["grid_lw"],
        alpha=STYLE_CFG["grid_alpha"]
    )

    plt.tight_layout()

    safe_feature_name = sanitize_feature_name(real_feature)

    dep_base = os.path.join(
        OUT_DIR,
        f"Supplementary_Fig_S5_SHAP_dependence_{safe_feature_name}_{shap_model_name}_{tag}_no_title"
    )

    dep_files = save_current_figure(dep_base)
    plt.show()
    plt.close()

    return {
        "feature": real_feature,
        "source": x_source,
        "is_categorical": False,
        "png": dep_files["png"],
        "svg": dep_files["svg"],
        "tiff": dep_files["tiff"]
    }

