# =========================================================
def _to_num(s):
    return pd.to_numeric(s, errors="coerce").replace([np.inf, -np.inf], np.nan)

def _safe_str(x):
    if pd.isna(x):
        return "<NA>"
    return str(x)

def _is_keras_like_model(m):
    t = str(type(m)).lower()
    return ("tensorflow" in t) or ("keras" in t)

def _safe_minmax(x):
    x = np.asarray(x, dtype=float)
    if len(x) == 0:
        return x
    mn = np.nanmin(x)
    mx = np.nanmax(x)
    if not np.isfinite(mn) or not np.isfinite(mx) or mx <= mn:
        return np.zeros_like(x, dtype=float)
    return (x - mn) / (mx - mn)

def predict_pos_proba(est, X):
    if hasattr(est, "predict_proba"):
        p = np.asarray(est.predict_proba(X))
        if p.ndim == 2 and p.shape[1] >= 2:
            return p[:, 1].ravel()
        if p.ndim == 1:
            return p.ravel()

    if _is_keras_like_model(est):
        p = np.asarray(est.predict(X, verbose=0)).reshape(-1)
        return np.clip(p, 0.0, 1.0)

    if hasattr(est, "decision_function"):
        z = np.asarray(est.decision_function(X)).ravel()
        return 1.0 / (1.0 + np.exp(-z))

    if hasattr(est, "predict"):
        p = np.asarray(est.predict(X)).ravel().astype(float)
        if np.nanmin(p) >= 0 and np.nanmax(p) <= 1:
            return p
        p_min, p_max = float(np.min(p)), float(np.max(p))
        if p_max > p_min:
            return (p - p_min) / (p_max - p_min)
        return np.zeros_like(p)

    raise RuntimeError("text predict_proba / decision_function / predict ")


# =========================================================
# 8) text -> text -> preprocessor.transform
# =========================================================
def candidate_to_X_for_payload(
    df_feat: pd.DataFrame,
    preprocessor_use,
    base_features_use,
    cat_cols_use,
    num_cols_use
):
    df0 = df_feat.copy()

    for c in cat_cols_use:
        if c in df0.columns:
            df0[c] = df0[c].fillna("<NA>").astype(str)

    for c in num_cols_use:
        if c in df0.columns:
            df0[c] = _to_num(df0[c])

    if "normalize_categorical_df" in globals() and callable(globals()["normalize_categorical_df"]):
        try:
            df0 = globals()["normalize_categorical_df"](df0, cat_cols_use)
        except Exception:
            pass

    if "apply_semantic_mapping" in globals() and callable(globals()["apply_semantic_mapping"]):
        try:
            df0 = globals()["apply_semantic_mapping"](df0)
        except Exception:
            pass

    if hasattr(preprocessor_use, "feature_names_in_"):
        need_cols = list(preprocessor_use.feature_names_in_)
        for c in need_cols:
            if c not in df0.columns:
                df0[c] = np.nan
        df0 = df0[need_cols]
    else:
        for c in base_features_use:
            if c not in df0.columns:
                df0[c] = np.nan
        df0 = df0[base_features_use]

    X = preprocessor_use.transform(df0)
    return X


