def compute_numeric_quantile_bounds(df_ref: pd.DataFrame, cols, q_low, q_high):
    bounds = {}
    for c in cols:
        x = _to_num(df_ref[c]).dropna()
        if len(x) < 5:
            continue
        bounds[c] = (float(x.quantile(q_low)), float(x.quantile(q_high)))
    return bounds

