def build_numeric_novelty_score(df_cand, df_ref, cols):
    if len(cols) == 0:
        return np.zeros(len(df_cand), dtype=float)

    scores = []
    for c in cols:
        if c not in df_cand.columns or c not in df_ref.columns:
            continue
        x_ref = _to_num(df_ref[c]).dropna()
        x_cand = _to_num(df_cand[c])

        if len(x_ref) < 5:
            continue

        med = float(x_ref.median())
        q1 = float(x_ref.quantile(0.25))
        q3 = float(x_ref.quantile(0.75))
        iqr = max(q3 - q1, 1e-9)

        s = np.abs(x_cand - med) / iqr
        s = s.fillna(np.nanmedian(s) if np.isfinite(np.nanmedian(s)) else 0.0)
        scores.append(np.asarray(s, dtype=float))

    if len(scores) == 0:
        return np.zeros(len(df_cand), dtype=float)

    raw = np.vstack(scores).mean(axis=0)
    return _safe_minmax(raw)

def build_categorical_novelty_score(df_cand, df_ref, cols):
    if len(cols) == 0:
        return np.zeros(len(df_cand), dtype=float)

    all_scores = []
    for c in cols:
        if c not in df_cand.columns or c not in df_ref.columns:
            continue

        ref_s = df_ref[c].fillna("<NA>").astype(str)
        cand_s = df_cand[c].fillna("<NA>").astype(str)

        freq = ref_s.value_counts(normalize=True).to_dict()
        s = cand_s.map(lambda v: 1.0 - float(freq.get(v, 0.0))).astype(float)
        all_scores.append(s.to_numpy())

    if len(all_scores) == 0:
        return np.zeros(len(df_cand), dtype=float)

    raw = np.vstack(all_scores).mean(axis=0)
    return _safe_minmax(raw)

def build_combo_novelty_score(df_cand, df_ref, cols):
    if len(cols) == 0:
        return np.zeros(len(df_cand), dtype=float)

    def make_key(df_):
        return df_[cols].fillna("<NA>").astype(str).agg("||".join, axis=1)

    ref_keys = set(make_key(df_ref))
    cand_keys = make_key(df_cand)
    raw = np.array([1.0 if k not in ref_keys else 0.0 for k in cand_keys], dtype=float)
    return raw

def build_dual_channel_outputs(df_scored, df_train_ref, out_dir, final_thr_value):
    df_sc = df_scored.copy()

    num_score = build_numeric_novelty_score(df_sc, df_train_ref, NUM_COLS_USE)
    cat_score = build_categorical_novelty_score(df_sc, df_train_ref, CAT_COLS_USE)
    combo_score = build_combo_novelty_score(df_sc, df_train_ref, CAT_COLS_USE)

    novelty_score = (
        NOVELTY_WEIGHT_NUM * num_score
        + NOVELTY_WEIGHT_CAT * cat_score
        + NOVELTY_WEIGHT_COMBO * combo_score
    )
    novelty_score = _safe_minmax(novelty_score)

    df_sc["novelty_num_score"] = num_score
    df_sc["novelty_cat_score"] = cat_score
    df_sc["novelty_combo_score"] = combo_score
    df_sc["novelty_score"] = novelty_score

    high_conf_df = df_sc.sort_values(
        ["pred_proba_model", "novelty_score"],
        ascending=[False, False]
    ).reset_index(drop=True)

    if DUAL_NOVELTY_MIN_PROBA is not None:
        min_prob = float(DUAL_NOVELTY_MIN_PROBA)
    elif final_thr_value is not None:
        min_prob = float(final_thr_value)
    else:
        min_prob = float(df_sc["pred_proba_model"].quantile(0.80))

    novelty_pool = df_sc[df_sc["pred_proba_model"] >= min_prob].copy()
    if len(novelty_pool) < max(20, DUAL_HIGH_NOVEL_TOPN):
        novelty_pool = df_sc.head(max(200, DUAL_HIGH_NOVEL_TOPN * 4)).copy()

    high_novel_df = novelty_pool.sort_values(
        ["novelty_score", "pred_proba_model"],
        ascending=[False, False]
    ).reset_index(drop=True)

    high_conf_path = os.path.join(out_dir, f"dual_channel_high_confidence_top{DUAL_HIGH_CONF_TOPN}.csv")
    high_novel_path = os.path.join(out_dir, f"dual_channel_high_novelty_top{DUAL_HIGH_NOVEL_TOPN}.csv")
    all_with_novelty_path = os.path.join(out_dir, "generated_candidates_scored_with_novelty.csv")

    df_sc.to_csv(all_with_novelty_path, index=False, encoding="utf-8-sig")
    high_conf_df.head(DUAL_HIGH_CONF_TOPN).to_csv(high_conf_path, index=False, encoding="utf-8-sig")
    high_novel_df.head(DUAL_HIGH_NOVEL_TOPN).to_csv(high_novel_path, index=False, encoding="utf-8-sig")

    return {
        "all_scored_with_novelty": all_with_novelty_path,
        "high_confidence_top_csv": high_conf_path,
        "high_novelty_top_csv": high_novel_path,
        "high_confidence_df": high_conf_df,
        "high_novelty_df": high_novel_df,
        "min_prob_for_novelty_channel": min_prob,
    }

