def export_commonality_summary_refined(df_scored, out_dir, topk_list):
    commonality_meta = {}

    def style_axis(ax, grid_axis="x"):
        ax.spines["top"].set_visible(False)
        ax.spines["right"].set_visible(False)
        ax.grid(axis=grid_axis, linestyle="--", alpha=0.15)
        ax.set_axisbelow(True)

    for topk in topk_list:
        topk = int(min(max(topk, 1), len(df_scored)))
        df_top = df_scored.head(topk).copy()

        num_rows = []
        for c in NUM_COLS_USE:
            if c not in df_top.columns:
                continue
            x = _to_num(df_top[c]).dropna()
            if len(x) < 3:
                continue
            num_rows.append({
                "feature": c,
                "n": int(len(x)),
                "mean": float(x.mean()),
                "median": float(x.median()),
                "q10": float(x.quantile(0.10)),
                "q25": float(x.quantile(0.25)),
                "q75": float(x.quantile(0.75)),
                "q90": float(x.quantile(0.90)),
                "min": float(x.min()),
                "max": float(x.max()),
            })

        num_summary_df = pd.DataFrame(num_rows)
        num_csv = os.path.join(out_dir, f"commonality_top{topk}_numeric_summary.csv")
        num_xlsx = os.path.join(out_dir, f"commonality_top{topk}_numeric_summary.xlsx")
        num_summary_df.to_csv(num_csv, index=False, encoding="utf-8-sig")
        num_summary_df.to_excel(num_xlsx, index=False)

        cat_rows = []
        for c in CAT_COLS_USE:
            if c not in df_top.columns:
                continue
            tab = df_top[c].fillna("<NA>").astype(str).value_counts(dropna=False)
            total = int(tab.sum()) if int(tab.sum()) > 0 else 1
            for val, cnt in tab.items():
                cat_rows.append({
                    "feature": c,
                    "value": str(val),
                    "count": int(cnt),
                    "freq": float(cnt / total),
                })

        cat_summary_df = pd.DataFrame(cat_rows)
        cat_csv = os.path.join(out_dir, f"commonality_top{topk}_categorical_frequency.csv")
        cat_xlsx = os.path.join(out_dir, f"commonality_top{topk}_categorical_frequency.xlsx")
        cat_summary_df.to_csv(cat_csv, index=False, encoding="utf-8-sig")
        cat_summary_df.to_excel(cat_xlsx, index=False)

        combo_csv = None
        combo_xlsx = None
        if len(CAT_COLS_USE) > 0:
            combo_tmp = df_top[CAT_COLS_USE].fillna("<NA>").astype(str).copy()
            combo_tmp["combo"] = combo_tmp[CAT_COLS_USE].agg(" || ".join, axis=1)
            combo_df = combo_tmp["combo"].value_counts().reset_index()
            combo_df.columns = ["combo", "count"]
            combo_df["freq"] = combo_df["count"] / float(combo_df["count"].sum())

            combo_csv = os.path.join(out_dir, f"commonality_top{topk}_combo_frequency.csv")
            combo_xlsx = os.path.join(out_dir, f"commonality_top{topk}_combo_frequency.xlsx")
            combo_df.to_csv(combo_csv, index=False, encoding="utf-8-sig")
            combo_df.to_excel(combo_xlsx, index=False)

        numeric_fig_path = None
        valid_num_cols = []
        for c in NUM_COLS_USE:
            if c in df_top.columns:
                s = _to_num(df_top[c]).dropna()
                if len(s) >= 3:
                    valid_num_cols.append(c)

        def _nice_admin_ticks(raw_max):
            cand = np.array([0, 0.2, 0.5, 1, 2, 5, 10, 20, 50, 100], dtype=float)
            upper = max(1.0, raw_max * 1.05)
            ticks_raw = cand[cand <= upper]
            if len(ticks_raw) == 0:
                ticks_raw = np.array([0, 1.0])
            ticks_plot = np.log1p(ticks_raw)
            tick_labels = [f"{t:g}" for t in ticks_raw]
            return ticks_plot, tick_labels

        if len(valid_num_cols) > 0:
            ncols = min(3, len(valid_num_cols))
            nrows = int(np.ceil(len(valid_num_cols) / ncols))
            fig, axes = plt.subplots(
                nrows=nrows, ncols=ncols,
                figsize=(4.2 * ncols, 4.6 * nrows)
            )
            axes = np.array(axes).reshape(-1)

            for ax, c in zip(axes, valid_num_cols):
                s_raw = _to_num(df_top[c]).dropna().to_numpy(dtype=float)

                if len(s_raw) == 0:
                    ax.axis("off")
                    continue

                if c == "Admin":
                    s_nonneg = np.clip(s_raw, 0, None)
                    s_plot = np.log1p(s_nonneg)

                    ax.boxplot(
                        s_plot,
                        widths=0.35,
                        patch_artist=True,
                        showfliers=False,
                        boxprops=dict(alpha=0.85),
                        medianprops=dict(linewidth=1.2),
                        whiskerprops=dict(linewidth=1.0),
                        capprops=dict(linewidth=1.0),
                    )

                    x_jitter = np.random.normal(loc=1.0, scale=0.03, size=len(s_plot))
                    ax.scatter(
                        x_jitter,
                        s_plot,
                        s=16,
                        alpha=0.40,
                        edgecolors="none"
                    )

                    raw_max = float(np.nanmax(s_nonneg))
                    tick_pos, tick_lab = _nice_admin_ticks(raw_max)
                    ax.set_yticks(tick_pos)
                    ax.set_yticklabels(tick_lab)

                    y_min = float(np.nanmin(s_plot))
                    y_max = float(np.nanmax(s_plot))
                    pad = (y_max - y_min) * 0.08 if y_max > y_min else 0.3
                    ax.set_ylim(max(0, y_min - pad), y_max + pad)

                    ax.set_title("Admin", fontsize=12, pad=8)
                    ax.set_ylabel("Value")

                else:
                    s_plot = s_raw.copy()

                    ax.boxplot(
                        s_plot,
                        widths=0.35,
                        patch_artist=True,
                        showfliers=False,
                        boxprops=dict(alpha=0.85),
                        medianprops=dict(linewidth=1.2),
                        whiskerprops=dict(linewidth=1.0),
                        capprops=dict(linewidth=1.0),
                    )

                    x_jitter = np.random.normal(loc=1.0, scale=0.03, size=len(s_plot))
                    ax.scatter(
                        x_jitter,
                        s_plot,
                        s=16,
                        alpha=0.40,
                        edgecolors="none"
                    )

                    y_min = float(np.nanmin(s_plot))
                    y_max = float(np.nanmax(s_plot))
                    pad = (y_max - y_min) * 0.08 if y_max > y_min else 1.0
                    ax.set_ylim(y_min - pad, y_max + pad)

                    ax.set_title(c, fontsize=12, pad=8)
                    ax.set_ylabel("Value")

                ax.set_xticks([])
                ax.spines["top"].set_visible(False)
                ax.spines["right"].set_visible(False)
                ax.grid(axis="y", linestyle="--", alpha=0.15)
                ax.set_axisbelow(True)

            for j in range(len(valid_num_cols), len(axes)):
                axes[j].axis("off")

            fig.suptitle(f"Top-{topk} candidate numeric distributions", y=1.02, fontsize=15)
            plt.tight_layout()
            numeric_fig_path = os.path.join(
                out_dir,
                f"commonality_top{topk}_numeric_distributions_refined_v5.png"
            )
            plt.savefig(numeric_fig_path, bbox_inches="tight")
            plt.show()
            plt.close(fig)

        cat_panel_fig_path = None
        if len(CAT_COLS_USE) > 0:
            n_panels = len(CAT_COLS_USE)
            ncols = 2
            nrows = int(np.ceil(n_panels / ncols))
            fig, axes = plt.subplots(nrows=nrows, ncols=ncols, figsize=(10.6, 3.6 * nrows))
            axes = np.array(axes).reshape(-1)

            for ax, c in zip(axes, CAT_COLS_USE):
                tab = (
                    df_top[c]
                    .fillna("<NA>")
                    .astype(str)
                    .value_counts(normalize=True, dropna=False)
                    .head(COMMONALITY_MAX_CAT_LEVELS)
                    .sort_values(ascending=True)
                    .reset_index()
                )
                tab.columns = ["value", "freq"]

                y_pos = np.arange(len(tab))
                ax.barh(
                    y=y_pos,
                    width=tab["freq"].to_numpy(),
                    height=0.55,
                    alpha=0.9
                )
                ax.set_yticks(y_pos)
                ax.set_yticklabels(tab["value"])
                ax.set_title(c, fontsize=12, pad=6)
                ax.set_xlabel("Frequency")
                ax.set_ylabel("")
                ax.set_xlim(0, max(0.05, tab["freq"].max() * 1.05))
                style_axis(ax, grid_axis="x")

            for j in range(len(CAT_COLS_USE), len(axes)):
                axes[j].axis("off")

            fig.suptitle(f"Top-{topk} candidate categorical frequencies", y=1.02, fontsize=15)
            plt.tight_layout()
            cat_panel_fig_path = os.path.join(out_dir, f"commonality_top{topk}_categorical_frequencies_refined_v2.png")
            plt.savefig(cat_panel_fig_path, bbox_inches="tight")
            plt.show()
            plt.close(fig)

        commonality_meta[topk] = {
            "numeric_summary_csv": num_csv,
            "numeric_summary_xlsx": num_xlsx,
            "categorical_frequency_csv": cat_csv,
            "categorical_frequency_xlsx": cat_xlsx,
            "combo_frequency_csv": combo_csv,
            "combo_frequency_xlsx": combo_xlsx,
            "numeric_distributions_png": numeric_fig_path,
            "categorical_frequencies_png": cat_panel_fig_path,
        }

    meta_path = os.path.join(out_dir, "commonality_summary_files_refined_v2.json")
    with open(meta_path, "w", encoding="utf-8") as f:
        json.dump(commonality_meta, f, ensure_ascii=False, indent=2)

    return commonality_meta, meta_path

