# 8) text -> text -> preprocessor.transform
# =========================================================
def candidate_to_X_for_payload(
    df_feat: pd.DataFrame,
    preprocessor_use,
    base_features_use,
    cat_cols_use,
    num_cols_use
):
    df0 = df_feat.copy()

    for c in cat_cols_use:
        if c in df0.columns:
            df0[c] = df0[c].fillna("<NA>").astype(str)

    for c in num_cols_use:
        if c in df0.columns:
            df0[c] = _to_num(df0[c])

    if "normalize_categorical_df" in globals() and callable(globals()["normalize_categorical_df"]):
        try:
            df0 = globals()["normalize_categorical_df"](df0, cat_cols_use)
        except Exception:
            pass

    if "apply_semantic_mapping" in globals() and callable(globals()["apply_semantic_mapping"]):
        try:
            df0 = globals()["apply_semantic_mapping"](df0)
        except Exception:
            pass

    if hasattr(preprocessor_use, "feature_names_in_"):
        need_cols = list(preprocessor_use.feature_names_in_)
        for c in need_cols:
            if c not in df0.columns:
                df0[c] = np.nan
        df0 = df0[need_cols]
    else:
        for c in base_features_use:
            if c not in df0.columns:
                df0[c] = np.nan
        df0 = df0[base_features_use]

    X = preprocessor_use.transform(df0)
    return X


