def build_paper_candidate_table(df_scored: pd.DataFrame, topk: int):
    df_top = df_scored.head(topk).copy().reset_index(drop=True)
    df_top.insert(0, "Rank", np.arange(1, len(df_top) + 1))

    keep_cols = ["Rank"]
    ordered_raw = ["Type", "MAT", "TS", "CT", "TM", "Shape", "Size", "Zeta Potential", "Admin"]
    for c in ordered_raw:
        if c in df_top.columns:
            keep_cols.append(c)

    # text
    if "pred_score" in df_top.columns:
        keep_cols.append("pred_score")
    elif "pred_proba_model" in df_top.columns:
        keep_cols.append("pred_proba_model")

    if "exploration_score" in df_top.columns:
        keep_cols.append("exploration_score")

    if "rank_model" in df_top.columns:
        keep_cols.append("rank_model")

    out = df_top[keep_cols].copy()
    rename_map = {
        "pred_score": "Predicted score",
        "pred_proba_model": "Predicted score",
        "exploration_score": "Exploration score",
        "rank_model": "Model rank",
    }
    out = out.rename(columns=rename_map)

    num_cols = out.select_dtypes(include=[np.number]).columns.tolist()
    out[num_cols] = out[num_cols].round(PAPER_ROUND_DECIMALS)

    return out

