def _filter_by_conditions(df: pd.DataFrame, filters: dict):
    out = df.copy()
    if filters is None:
        return out

    for col, val in filters.items():
        if col not in out.columns:
            raise KeyError(f"text {col}")

        if isinstance(val, (list, tuple, set)):
            val_set = set(str(x) for x in val)
            out = out[out[col].fillna("<NA>").astype(str).isin(val_set)]
        else:
            out = out[out[col].fillna("<NA>").astype(str) == str(val)]

    return out.reset_index(drop=True)

def _format_window(low, high, decimals=3):
    if pd.isna(low) or pd.isna(high):
        return ""
    return f"{round(float(low), decimals)} – {round(float(high), decimals)}"

def build_range_recommendation(
    df_scored: pd.DataFrame,
    filters: dict = None,
    topn: int = 20,
    numeric_cols=None,
    q_low: float = 0.25,
    q_high: float = 0.75,
    min_prob=None,
    min_n: int = 5,
    round_decimals: int = 3,
):
    if numeric_cols is None:
        numeric_cols = ["Size", "Zeta Potential", "Admin"]

    df_use = _filter_by_conditions(df_scored, filters)

    if min_prob is not None:
        df_use = df_use[df_use["pred_proba_model"] >= float(min_prob)].copy()

    df_use = (
        df_use
        .sort_values(["pred_proba_model"], ascending=[False])
        .reset_index(drop=True)
    )

    if topn is not None:
        df_use = df_use.head(min(int(topn), len(df_use))).copy()

    if len(df_use) < min_n:
        raise ValueError(
            f"text text n={len(df_use)} text RANGE_MIN_N={min_n} "
        )

    rows = []
    for col in numeric_cols:
        if col not in df_use.columns:
            continue

        s = _to_num(df_use[col]).dropna()
        if len(s) < min_n:
            continue

        ql = float(s.quantile(q_low))
        med = float(s.median())
        qh = float(s.quantile(q_high))
        mean_ = float(s.mean())
        min_ = float(s.min())
        max_ = float(s.max())

        rows.append({
            "feature": col,
            "n": int(len(s)),
            "q_low": q_low,
            "q_high": q_high,
            "lower": ql,
            "median": med,
            "upper": qh,
            "mean": mean_,
            "min": min_,
            "max": max_,
            "recommended_window": _format_window(ql, qh, decimals=round_decimals),
        })

    window_df = pd.DataFrame(rows)

    pretty_df = window_df.copy()
    if not pretty_df.empty:
        pretty_df["feature"] = pretty_df["feature"].replace({
            "Size": "Size text",
            "Zeta Potential": "Zeta Potential text",
            "Admin": "Admin text",
        })
        pretty_df = pretty_df[[
            "feature", "recommended_window", "median", "n"
        ]].rename(columns={
            "feature": "Parameter",
            "recommended_window": "Recommended window",
            "median": "Median",
            "n": "Candidates used",
        })

    meta = {
        "filters": filters,
        "topn_used": int(len(df_use)),
        "q_low": q_low,
        "q_high": q_high,
        "min_prob": None if min_prob is None else float(min_prob),
        "numeric_cols": numeric_cols,
    }

    return df_use, window_df, pretty_df, meta

