def _filter_by_conditions(df: pd.DataFrame, filters: dict):
    out = df.copy()
    if filters is None:
        return out

    for col, val in filters.items():
        if col not in out.columns:
            raise KeyError(f"text {col}")

        if isinstance(val, (list, tuple, set)):
            val_set = set(str(x) for x in val)
            out = out[out[col].fillna("<NA>").astype(str).isin(val_set)]
        else:
            out = out[out[col].fillna("<NA>").astype(str) == str(val)]

    return out.reset_index(drop=True)

def build_range_recommendation(
    df_scored: pd.DataFrame,
    filters: dict = None,
    topn: int = 20,
    numeric_cols=None,
    q_low: float = 0.25,
    q_high: float = 0.75,
    min_prob=None,
    min_n: int = 5,
    round_decimals: int = 3,
):
    if numeric_cols is None:
        numeric_cols = ["Size", "Zeta Potential", "Admin"]

    df_use = _filter_by_conditions(df_scored, filters)

    if min_prob is not None:
        df_use = df_use[df_use["pred_score"] >= float(min_prob)].copy()

    df_use = df_use.sort_values(["pred_score"], ascending=[False]).reset_index(drop=True)
    df_use = df_use.head(min(int(topn), len(df_use))).copy()

    if len(df_use) < min_n:
        raise ValueError(f"text text n={len(df_use)} text RANGE_MIN_N={min_n} ")

    rows = []
    for col in numeric_cols:
        if col not in df_use.columns:
            continue

        if col == "Size":
            s = _to_num(df_use[col]).dropna()
            if len(s) < min_n:
                continue
            s_nm = np.power(10.0, s.to_numpy(dtype=float))
            ql = float(np.quantile(s_nm, q_low))
            med = float(np.median(s_nm))
            qh = float(np.quantile(s_nm, q_high))
            rows.append({
                "Parameter": "Size text",
                "Recommended window": f"{round(ql, 0)} – {round(qh, 0)} nm",
                "Median": round(med, 0),
                "Candidates used": int(len(s_nm)),
            })
        else:
            s = _to_num(df_use[col]).dropna()
            if len(s) < min_n:
                continue
            ql = float(s.quantile(q_low))
            med = float(s.median())
            qh = float(s.quantile(q_high))
            rows.append({
                "Parameter": f"{col} text",
                "Recommended window": f"{round(ql, round_decimals)} – {round(qh, round_decimals)}",
                "Median": round(med, round_decimals),
                "Candidates used": int(len(s)),
            })

    return pd.DataFrame(rows)


