def resolve_primary_model_name():
    force_name = globals().get("FORCE_PRIMARY_MODEL_NAME", None)
    if force_name is not None:
        return str(force_name)

    if "PRIMARY_MODEL_NAME" in globals() and globals()["PRIMARY_MODEL_NAME"] is not None:
        return str(globals()["PRIMARY_MODEL_NAME"])

    if "selected_primary_model_name" in globals() and globals()["selected_primary_model_name"] is not None:
        return str(globals()["selected_primary_model_name"])

    if "model_metrics_oof_df" in globals() and globals()["model_metrics_oof_df"] is not None:
        tmp_oof_df = globals()["model_metrics_oof_df"]
        if isinstance(tmp_oof_df, pd.DataFrame) and not tmp_oof_df.empty:
            return str(tmp_oof_df.iloc[0]["model_name"])

    return str(model_metrics_test_df.iloc[0]["model_name"])

def pick_best_single_model_name():
    if "model_metrics_oof_df" in globals() and globals()["model_metrics_oof_df"] is not None:
        tmp_oof_df = globals()["model_metrics_oof_df"]
        if isinstance(tmp_oof_df, pd.DataFrame) and not tmp_oof_df.empty:
            ranked_names = tmp_oof_df["model_name"].astype(str).tolist()
            for name in ranked_names:
                if name not in ENSEMBLE_MODELS:
                    return name

    ranked_names = model_metrics_test_df["model_name"].astype(str).tolist()
    for name in ranked_names:
        if name not in ENSEMBLE_MODELS:
            return name

    raise RuntimeError("text ")

