def load_payload(model_name, save_dir):
    if model_name in globals() and globals()[model_name] is not None:
        obj = globals()[model_name]
        if isinstance(obj, dict):
            return obj, f"memory:{model_name}"

    cand1 = os.path.join(save_dir, f"{model_name}.joblib")
    if os.path.exists(cand1):
        obj = joblib.load(cand1)
        if isinstance(obj, dict):
            return obj, f"joblib:{cand1}"

    cand2 = os.path.join(save_dir, "saved_models", f"{model_name}.joblib")
    if os.path.exists(cand2):
        obj = joblib.load(cand2)
        if isinstance(obj, dict):
            return obj, f"joblib:{cand2}"

    if "loaded_model_payloads" in globals():
        lmp = globals()["loaded_model_payloads"]
        if isinstance(lmp, dict) and model_name in lmp:
            item = lmp[model_name]
            if isinstance(item, dict) and "payload" in item and isinstance(item["payload"], dict):
                return item["payload"], f"loaded_model_payloads:{model_name}"

    return None, None

def resolve_estimator_from_payload(model_name, payload):
    estimator = payload.get("estimator", None)
    if estimator is not None:
        return estimator, "payload.estimator"

    model_path = payload.get("model_path", None)
    if model_path is None:
        return None, None

    if not os.path.isabs(model_path):
        cand1 = os.path.join(SAVE_DIR, model_path)
        cand2 = os.path.join(SAVE_DIR, "saved_models", model_path)
        if os.path.exists(cand1):
            model_path = cand1
        elif os.path.exists(cand2):
            model_path = cand2

    if not os.path.exists(model_path):
        raise RuntimeError(f"payload text model_path text {model_path}")

    if str(model_path).lower().endswith(".cbm"):
        if CatBoostClassifier is None:
            raise RuntimeError("text .cbm text text import catboost ")
        m = CatBoostClassifier()
        m.load_model(model_path)
        return m, f"CatBoost.load_model({model_path})"

    if str(model_path).lower().endswith(".keras") or str(model_path).lower().endswith(".h5"):
        if not _HAS_TF:
            raise RuntimeError("text keras text text import tensorflow ")
        m = tf.keras.models.load_model(model_path)
        return m, f"tf.keras.models.load_model({model_path})"

    m = joblib.load(model_path)
    return m, f"joblib({model_path})"

def resolve_payload_bundle(model_name, save_dir):
    payload_i, payload_source_i = load_payload(model_name, save_dir)
    if payload_i is None:
        raise RuntimeError(f"text {model_name} text payload ")

    model_i, model_source_i = resolve_estimator_from_payload(model_name, payload_i)
    if model_i is None:
        raise RuntimeError(f"{model_name} text estimator ")

    preprocessor_i = payload_i.get("preprocessor", None)
    if preprocessor_i is None and "preprocessor" in globals() and globals()["preprocessor"] is not None:
        preprocessor_i = globals()["preprocessor"]
    if preprocessor_i is None:
        raise RuntimeError(f"{model_name} text preprocessor ")

    num_i = list(payload_i.get("numeric_features", []))
    cat_i = list(payload_i.get("categorical_features", []))

    if (len(num_i) == 0 or len(cat_i) == 0) and "prep_meta" in globals():
        prep_meta = globals()["prep_meta"]
        num_i = list(prep_meta.get("numeric_features", num_i))
        cat_i = list(prep_meta.get("categorical_features", cat_i))

    base_i = list(payload_i.get("base_features", []))
    if len(base_i) == 0 and "prep_meta" in globals() and globals()["prep_meta"] is not None:
        base_i = list(globals()["prep_meta"].get("base_features", []))
    if len(base_i) == 0:
        base_i = cat_i + num_i

    base_i = [c for c in base_i if c in df_train.columns]
    num_i = [c for c in num_i if c in df_train.columns]
    cat_i = [c for c in cat_i if c in df_train.columns]

    return {
        "model_name": model_name,
        "payload": payload_i,
        "payload_source": payload_source_i,
        "model": model_i,
        "model_source": model_source_i,
        "preprocessor": preprocessor_i,
        "base_features": base_i,
        "num_cols": num_i,
        "cat_cols": cat_i,
    }

