def build_paper_candidate_table(df_scored: pd.DataFrame, topk: int):
    df_top = df_scored.head(topk).copy().reset_index(drop=True)

    df_top = ensure_local_intervals_on_df(df_top)

    if "Size" in df_top.columns and "Size (nm)" not in df_top.columns:
        df_top["Size (nm)"] = df_top["Size"].apply(_size_log_to_nm)

    df_top.insert(0, "Rank", np.arange(1, len(df_top) + 1))

    keep_cols = ["Rank"]

    if "Type" in df_top.columns: keep_cols.append("Type")
    if "MAT" in df_top.columns: keep_cols.append("MAT")
    if "TS" in df_top.columns: keep_cols.append("TS")
    if "CT" in df_top.columns: keep_cols.append("CT")
    if "TM" in df_top.columns: keep_cols.append("TM")
    if "Shape" in df_top.columns: keep_cols.append("Shape")

    if "Size" in df_top.columns: keep_cols.append("Size")
    if "Size (nm)" in df_top.columns: keep_cols.append("Size (nm)")
    if "Size local interval" in df_top.columns: keep_cols.append("Size local interval")

    if "Zeta Potential" in df_top.columns: keep_cols.append("Zeta Potential")
    if "Zeta Potential local interval" in df_top.columns: keep_cols.append("Zeta Potential local interval")

    if "Admin" in df_top.columns: keep_cols.append("Admin")
    if "Admin local interval" in df_top.columns: keep_cols.append("Admin local interval")

    if "pred_score" in df_top.columns: keep_cols.append("pred_score")
    if "exploration_score" in df_top.columns: keep_cols.append("exploration_score")
    if "rank_model" in df_top.columns: keep_cols.append("rank_model")

    out = df_top[keep_cols].copy()

    rename_map = {
        "Size": "Size (log10)",
        "pred_score": "Predicted score",
        "exploration_score": "Exploration score",
        "rank_model": "Model rank",
    }
    out = out.rename(columns=rename_map)

    num_cols = out.select_dtypes(include=[np.number]).columns.tolist()
    out[num_cols] = out[num_cols].round(PAPER_ROUND_DECIMALS)

    return out


