def _to_num(s):
    return pd.to_numeric(s, errors="coerce").replace([np.inf, -np.inf], np.nan)

def _safe_str(x):
    if pd.isna(x):
        return "<NA>"
    return str(x)

def safe_display(df_obj):
    try:
        display(df_obj)
    except Exception:
        print(df_obj)

def _is_keras_like_model(m):
    t = str(type(m)).lower()
    return ("tensorflow" in t) or ("keras" in t)

def _safe_filename_text(x):
    s = str(x)
    keep = []
    for ch in s:
        if ch.isalnum() or ch in ["-", "_"]:
            keep.append(ch)
        else:
            keep.append("_")
    return "".join(keep)

def _get_display_decimals(col):
    if isinstance(LOCAL_INTERVAL_DISPLAY_DECIMALS, dict):
        return int(LOCAL_INTERVAL_DISPLAY_DECIMALS.get(col, 1))
    return int(LOCAL_INTERVAL_DISPLAY_DECIMALS)

def _format_interval(lo, hi, col):
    if pd.isna(lo) or pd.isna(hi):
        return ""
    d = _get_display_decimals(col)
    return f"{round(float(lo), d)} – {round(float(hi), d)}"

def _size_log_to_nm(x_log):
    return float(10 ** float(x_log))

def _size_nm_to_log(x_nm):
    x_nm = max(float(x_nm), 1e-12)
    return float(np.log10(x_nm))

def _is_breast_only_filter(filters):
    return isinstance(filters, dict) and len(filters) == 1 and str(filters.get("CT")) == "Breast"


