def predict_pos_proba(est, X):
    if hasattr(est, "predict_proba"):
        p = np.asarray(est.predict_proba(X))
        if p.ndim == 2 and p.shape[1] >= 2:
            return p[:, 1].ravel()
        if p.ndim == 1:
            return p.ravel()

    if _is_keras_like_model(est):
        p = np.asarray(est.predict(X, verbose=0)).reshape(-1)
        return np.clip(p, 0.0, 1.0)

    if hasattr(est, "decision_function"):
        z = np.asarray(est.decision_function(X)).ravel()
        return 1.0 / (1.0 + np.exp(-z))

    if hasattr(est, "predict"):
        p = np.asarray(est.predict(X)).ravel().astype(float)
        if np.nanmin(p) >= 0 and np.nanmax(p) <= 1:
            return p
        p_min, p_max = float(np.min(p)), float(np.max(p))
        if p_max > p_min:
            return (p - p_min) / (p_max - p_min)
        return np.zeros_like(p)

    raise RuntimeError("text predict_proba / decision_function / predict ")


