LOCAL_INTERVAL_CACHE = {}

def _get_abs_bounds_for_col(col, x0):
    if col in FEAS_ABS_RANGES:
        lo, hi = FEAS_ABS_RANGES[col]
        return float(lo), float(hi)

    x_ref = _to_num(df_train[col]).dropna() if col in df_train.columns else pd.Series(dtype=float)
    if len(x_ref) >= 5:
        lo = float(x_ref.quantile(0.01))
        hi = float(x_ref.quantile(0.99))
        return lo, hi

    return float(x0 - 1.0), float(x0 + 1.0)

def _get_min_half_width(col):
    if isinstance(LOCAL_INTERVAL_MIN_HALF_WIDTHS, dict):
        return float(LOCAL_INTERVAL_MIN_HALF_WIDTHS.get(col, 0.1))
    return float(LOCAL_INTERVAL_MIN_HALF_WIDTHS)

def _single_size_local_interval_for_candidate_nm(row: pd.Series):
    col = "Size"

    if col not in row.index or pd.isna(row[col]):
        return {
            "Size local lower": np.nan,
            "Size local upper": np.nan,
            "Size local interval": "",
        }

    x0_log = float(row[col])
    x0_nm = _size_log_to_nm(x0_log)
    current_score = float(row["pred_score"])

    x_ref_log = _to_num(df_train[col]).dropna() if col in df_train.columns else pd.Series(dtype=float)

    if len(x_ref_log) >= 5:
        x_ref_nm = np.power(10.0, x_ref_log.to_numpy(dtype=float))
        ref_lo = float(np.quantile(x_ref_nm, 0.01))
        ref_hi = float(np.quantile(x_ref_nm, 0.99))
    else:
        ref_lo = max(1.0, x0_nm * 0.7)
        ref_hi = x0_nm * 1.3

    ref_span_nm = max(ref_hi - ref_lo, 1.0)

    half_nm = max(
        x0_nm * SIZE_NM_REL_RADIUS,
        ref_span_nm * SIZE_NM_REF_SPAN_FRAC,
        SIZE_NM_MIN_HALF_WIDTH,
    )

    best_lo_nm, best_hi_nm = x0_nm, x0_nm

    for _ in range(max(1, SIZE_LOCAL_EXPAND_STEPS)):
        lo_nm = max(ref_lo, x0_nm - half_nm)
        hi_nm = min(ref_hi, x0_nm + half_nm)

        if hi_nm <= lo_nm:
            break

        grid_nm = np.linspace(lo_nm, hi_nm, LOCAL_INTERVAL_GRID_SIZE)
        grid_nm = np.unique(np.sort(np.r_[grid_nm, x0_nm]))
        center_idx = int(np.argmin(np.abs(grid_nm - x0_nm)))

        tmp = pd.DataFrame([row.to_dict()] * len(grid_nm))
        tmp["Size"] = [_size_nm_to_log(v) for v in grid_nm]

        X_tmp = candidate_to_X_for_payload(
            df_feat=tmp[base_features].copy(),
            preprocessor_use=preprocessor,
            base_features_use=base_features,
            cat_cols_use=CAT_COLS_USE,
            num_cols_use=NUM_COLS_USE
        )

        pred_tmp = predict_pos_proba(model, X_tmp)

        local_thr = current_score * SIZE_LOCAL_SCORE_RATIO

        if LOCAL_INTERVAL_MIN_SCORE is not None:
            local_thr = max(local_thr, float(LOCAL_INTERVAL_MIN_SCORE))

        if LOCAL_INTERVAL_USE_FINAL_THR and final_thr is not None and current_score >= float(final_thr):
            local_thr = max(local_thr, float(final_thr))

        if pred_tmp[center_idx] < local_thr:
            local_thr = min(local_thr, float(pred_tmp[center_idx]))

        ok = pred_tmp >= local_thr

        left = center_idx
        right = center_idx

        while left - 1 >= 0 and ok[left - 1]:
            left -= 1

        while right + 1 < len(ok) and ok[right + 1]:
            right += 1

        best_lo_nm = float(grid_nm[left])
        best_hi_nm = float(grid_nm[right])

        touch_left = (left == 0) and (lo_nm > ref_lo + 1e-12)
        touch_right = (right == len(grid_nm) - 1) and (hi_nm < ref_hi - 1e-12)

        if touch_left or touch_right:
            half_nm *= SIZE_LOCAL_EXPAND_FACTOR
        else:
            break

    disp = f"{round(best_lo_nm, SIZE_NM_DISPLAY_DECIMALS)} – {round(best_hi_nm, SIZE_NM_DISPLAY_DECIMALS)} nm"

    return {
        "Size local lower": best_lo_nm,
        "Size local upper": best_hi_nm,
        "Size local interval": disp,
    }

def _single_local_interval_for_candidate(row: pd.Series, col: str):
    if col == "Size" and SIZE_USE_NM_LOCAL_INTERVAL:
        return _single_size_local_interval_for_candidate_nm(row)

    if col not in row.index or pd.isna(row[col]):
        return {
            f"{col} local lower": np.nan,
            f"{col} local upper": np.nan,
            f"{col} local interval": "",
        }

    x0 = float(row[col])
    current_score = float(row["pred_score"])

    abs_lo, abs_hi = _get_abs_bounds_for_col(col, x0)
    if abs_hi <= abs_lo:
        abs_lo, abs_hi = x0 - 1.0, x0 + 1.0

    x_ref = _to_num(df_train[col]).dropna() if col in df_train.columns else pd.Series(dtype=float)

    if len(x_ref) >= 5:
        ref_span = float(x_ref.quantile(0.99) - x_ref.quantile(0.01))
    else:
        ref_span = max(abs(x0), 1.0)

    half = max(
        abs(x0) * LOCAL_INTERVAL_REL_RADIUS,
        ref_span * LOCAL_INTERVAL_REF_SPAN_FRAC,
        _get_min_half_width(col),
    )

    best_lo, best_hi = x0, x0

    for _ in range(max(1, LOCAL_INTERVAL_EXPAND_STEPS)):
        lo = max(abs_lo, x0 - half)
        hi = min(abs_hi, x0 + half)

        if hi <= lo:
            break

        grid = np.linspace(lo, hi, LOCAL_INTERVAL_GRID_SIZE)
        grid = np.unique(np.sort(np.r_[grid, x0]))
        center_idx = int(np.argmin(np.abs(grid - x0)))

        tmp = pd.DataFrame([row.to_dict()] * len(grid))
        tmp[col] = grid

        X_tmp = candidate_to_X_for_payload(
            df_feat=tmp[base_features].copy(),
            preprocessor_use=preprocessor,
            base_features_use=base_features,
            cat_cols_use=CAT_COLS_USE,
            num_cols_use=NUM_COLS_USE
        )

        pred_tmp = predict_pos_proba(model, X_tmp)

        local_thr = current_score * LOCAL_INTERVAL_SCORE_RATIO

        if LOCAL_INTERVAL_MIN_SCORE is not None:
            local_thr = max(local_thr, float(LOCAL_INTERVAL_MIN_SCORE))

        if LOCAL_INTERVAL_USE_FINAL_THR and final_thr is not None and current_score >= float(final_thr):
            local_thr = max(local_thr, float(final_thr))

        if pred_tmp[center_idx] < local_thr:
            local_thr = min(local_thr, float(pred_tmp[center_idx]))

        ok = pred_tmp >= local_thr

        left = center_idx
        right = center_idx

        while left - 1 >= 0 and ok[left - 1]:
            left -= 1

        while right + 1 < len(ok) and ok[right + 1]:
            right += 1

        best_lo = float(grid[left])
        best_hi = float(grid[right])

        touch_left = (left == 0) and (lo > abs_lo + 1e-12)
        touch_right = (right == len(grid) - 1) and (hi < abs_hi - 1e-12)

        if touch_left or touch_right:
            half *= LOCAL_INTERVAL_EXPAND_FACTOR
        else:
            break

    return {
        f"{col} local lower": best_lo,
        f"{col} local upper": best_hi,
        f"{col} local interval": _format_interval(best_lo, best_hi, col),
    }

def _compute_local_interval_record(row: pd.Series):
    rec = {}

    for col in LOCAL_INTERVAL_NUMERIC_COLS:
        rec.update(_single_local_interval_for_candidate(row, col))

    return rec

def ensure_local_intervals_on_df(df_in: pd.DataFrame):
    if not ENABLE_LOCAL_ROBUST_INTERVALS:
        return df_in.copy()

    out = df_in.copy()

    if "_candidate_id" not in out.columns:
        return out

    need_rows = []

    for _, row in out.iterrows():
        cid = int(row["_candidate_id"])
        if cid not in LOCAL_INTERVAL_CACHE:
            need_rows.append(row)

    for row in need_rows:
        cid = int(row["_candidate_id"])
        LOCAL_INTERVAL_CACHE[cid] = _compute_local_interval_record(row)

    for col in LOCAL_INTERVAL_NUMERIC_COLS:
        lower_col = f"{col} local lower"
        upper_col = f"{col} local upper"
        disp_col = f"{col} local interval"

        out[lower_col] = out["_candidate_id"].map(
            lambda cid: LOCAL_INTERVAL_CACHE[int(cid)].get(lower_col, np.nan)
        )
        out[upper_col] = out["_candidate_id"].map(
            lambda cid: LOCAL_INTERVAL_CACHE[int(cid)].get(upper_col, np.nan)
        )
        out[disp_col] = out["_candidate_id"].map(
            lambda cid: LOCAL_INTERVAL_CACHE[int(cid)].get(disp_col, "")
        )

    return out


# =========================================================
# 12) text text Breast text Size/Zeta/Admin text
# =========================================================
def _filter_by_conditions(df: pd.DataFrame, filters: dict):
    out = df.copy()

    if filters is None:
        return out

    for col, val in filters.items():
        if col not in out.columns:
            raise KeyError(f"text {col}")

        if isinstance(val, (list, tuple, set)):
            val_set = set(str(x) for x in val)
            out = out[out[col].fillna("<NA>").astype(str).isin(val_set)]
        else:
            out = out[out[col].fillna("<NA>").astype(str) == str(val)]

    return out.reset_index(drop=True)

def build_range_recommendation(
    df_scored: pd.DataFrame,
    filters: dict = None,
    topn: int = 20,
    numeric_cols=None,
    q_low: float = 0.25,
    q_high: float = 0.75,
    min_prob=None,
    min_n: int = 5,
    round_decimals: int = 3,
):
    if numeric_cols is None:
        numeric_cols = ["Size", "Zeta Potential", "Admin"]

    df_use = _filter_by_conditions(df_scored, filters)

    if min_prob is not None:
        df_use = df_use[df_use["pred_score"] >= float(min_prob)].copy()

    df_use = df_use.sort_values(["pred_score"], ascending=[False]).reset_index(drop=True)
    df_use = df_use.head(min(int(topn), len(df_use))).copy()

    if len(df_use) < min_n:
        raise ValueError(f"text text n={len(df_use)} text RANGE_MIN_N={min_n} ")

    rows = []

    for col in numeric_cols:
        if col not in df_use.columns:
            continue

        if col == "Size":
            s = _to_num(df_use[col]).dropna()
            if len(s) < min_n:
                continue

            s_nm = np.power(10.0, s.to_numpy(dtype=float))
            ql = float(np.quantile(s_nm, q_low))
            med = float(np.median(s_nm))
            qh = float(np.quantile(s_nm, q_high))

            rows.append({
                "Parameter": "Size",
                "Recommended window": f"{round(ql, 0)} – {round(qh, 0)} nm",
                "Median": round(med, 0),
                "Unit": "nm",
                "Candidates used": int(len(s_nm)),
            })

        else:
            s = _to_num(df_use[col]).dropna()
            if len(s) < min_n:
                continue

            ql = float(s.quantile(q_low))
            med = float(s.median())
            qh = float(s.quantile(q_high))

            unit = "mV" if col == "Zeta Potential" else "mg/kg" if col == "Admin" else ""

            rows.append({
                "Parameter": col,
                "Recommended window": f"{round(ql, round_decimals)} – {round(qh, round_decimals)}",
                "Median": round(med, round_decimals),
                "Unit": unit,
                "Candidates used": int(len(s)),
            })

    return pd.DataFrame(rows)


