# 13) text
# =========================================================
def build_paper_candidate_table(df_scored: pd.DataFrame, topk: int):
    df_top = df_scored.head(topk).copy().reset_index(drop=True)

    df_top = ensure_local_intervals_on_df(df_top)

    if "Size" in df_top.columns and "Size (nm)" not in df_top.columns:
        df_top["Size (nm)"] = df_top["Size"].apply(_size_log_to_nm)

    df_top.insert(0, "Rank", np.arange(1, len(df_top) + 1))

    keep_cols = ["Rank"]

    for c in ["Type", "MAT", "TS", "CT", "TM", "Shape"]:
        if c in df_top.columns:
            keep_cols.append(c)

    if "Size" in df_top.columns:
        keep_cols.append("Size")
    if "Size (nm)" in df_top.columns:
        keep_cols.append("Size (nm)")
    if "Size local interval" in df_top.columns:
        keep_cols.append("Size local interval")

    if "Zeta Potential" in df_top.columns:
        keep_cols.append("Zeta Potential")
    if "Zeta Potential local interval" in df_top.columns:
        keep_cols.append("Zeta Potential local interval")

    if "Admin" in df_top.columns:
        keep_cols.append("Admin")
    if "Admin local interval" in df_top.columns:
        keep_cols.append("Admin local interval")

    if "pred_proba_high" in df_top.columns:
        keep_cols.append("pred_proba_high")
    if "rank_model" in df_top.columns:
        keep_cols.append("rank_model")

    out = df_top[keep_cols].copy()

    rename_map = {
        "Size": "Size (log10)",
        "pred_proba_high": "Predicted high-delivery probability",
        "rank_model": "Model rank",
    }

    out = out.rename(columns=rename_map)

    num_cols = out.select_dtypes(include=[np.number]).columns.tolist()
    out[num_cols] = out[num_cols].round(PAPER_ROUND_DECIMALS)

    return out


