def _resolve_ct_values(df_scored: pd.DataFrame, ct_values):
    if "CT" not in df_scored.columns:
        return []

    all_ct = (
        df_scored["CT"]
        .fillna("<NA>")
        .astype(str)
        .drop_duplicates()
        .tolist()
    )

    if ct_values is None:
        return []

    if isinstance(ct_values, str) and ct_values.lower() == "auto":
        return sorted(all_ct)

    if isinstance(ct_values, (list, tuple, set)):
        out = []
        for v in ct_values:
            v = str(v)
            if v in all_ct:
                out.append(v)
        return out

    v = str(ct_values)
    return [v] if v in all_ct else []

def export_ct_subtables(df_scored: pd.DataFrame, out_dir: str, ct_values, topn: int = 20):
    outputs = {}

    if "CT" not in df_scored.columns:
        return outputs, None

    ct_list = _resolve_ct_values(df_scored, ct_values)

    if len(ct_list) == 0:
        return outputs, None

    for ct_name in ct_list:
        df_ct = (
            df_scored[df_scored["CT"].fillna("<NA>").astype(str) == str(ct_name)]
            .sort_values(["pred_score"], ascending=[False])
            .reset_index(drop=True)
        )

        if df_ct.empty:
            continue

        topk = int(min(max(topn, 1), len(df_ct)))
        ct_tag = _safe_filename_text(ct_name)

        raw_csv = os.path.join(out_dir, f"generated_CT_{ct_tag}_top{topk}.csv")
        df_ct.head(topk).to_csv(raw_csv, index=False, encoding="utf-8-sig")

        paper_df = build_paper_candidate_table(df_ct, topk=topk)

        paper_csv = os.path.join(out_dir, f"paper_candidate_table_CT_{ct_tag}_top{topk}.csv")
        paper_xlsx = os.path.join(out_dir, f"paper_candidate_table_CT_{ct_tag}_top{topk}.xlsx")

        paper_df.to_csv(paper_csv, index=False, encoding="utf-8-sig")
        paper_df.to_excel(paper_xlsx, index=False)

        outputs[str(ct_name)] = {
            "ct": ct_name,
            "n_total_in_ct": int(len(df_ct)),
            "topn": int(topk),
            "raw_top_csv": raw_csv,
            "paper_csv": paper_csv,
            "paper_xlsx": paper_xlsx,
        }

    meta_path = os.path.join(out_dir, f"ct_subtables_top{topn}_files.json")
    with open(meta_path, "w", encoding="utf-8") as f:
        json.dump(outputs, f, ensure_ascii=False, indent=2)

    return outputs, meta_path

